  'SỐ BÁO DANH': string | number;
  'MÃ HỌC VIÊN': string | number;
  'HỌ VÀ TÊN': string;
  'SỐ CHỨNG MINH'?: string | number;
  'NGÀY SINH'?: string | number;
  'NƠI CƯ TRÚ'?: string;
  'HẠNG GPLX': string;
  'NỘI DUNG THI': string;
  'LÝ THUYẾT': string;
  'MÔ PHỎNG': string;
  'SA HÌNH': string;
