import type { StudentRecord, TrainingUnit } from '../types';

export const getResultStatus = (result: string | undefined | null): { participated: boolean, passed: boolean } => {
    const normalized = typeof result === 'string' ? result.trim().toUpperCase() : '';
    if (normalized === '' || normalized === 'VẮNG') return { participated: false, passed: false };
    return { participated: true, passed: normalized === 'ĐẠT' };
};

export const isStudentAbsent = (record: StudentRecord): boolean => {
    const theory = getResultStatus(record['LÝ THUYẾT']);
    const simulation = getResultStatus(record['MÔ PHỎNG']);
    const practical = getResultStatus(record['SA HÌNH']);
    const onRoad = getResultStatus(record['ĐƯỜNG TRƯỜNG']);
    return !theory.participated && !simulation.participated && !practical.participated && !onRoad.participated;
};

export const isStudentPassed = (record: StudentRecord): boolean => {
    if (isStudentAbsent(record)) return false;

    let noiDungThi = (record['NỘI DUNG THI'] || '').toString().trim().toUpperCase();
    noiDungThi = noiDungThi.replace(/Đ/g, 'D');

    if (noiDungThi.length === 0) return false;

    const requiredTestsPassed =
        (!noiDungThi.includes('L') || getResultStatus(record['LÝ THUYẾT']).passed) &&
        (!noiDungThi.includes('M') || getResultStatus(record['MÔ PHỎNG']).passed) &&
        (!noiDungThi.includes('H') || getResultStatus(record['SA HÌNH']).passed) &&
        (!noiDungThi.includes('D') || getResultStatus(record['ĐƯỜNG TRƯỜNG']).passed);

    return requiredTestsPassed;
};

export const generateClassSummaryString = (students: StudentRecord[]): string => {
    if (!students || students.length === 0) return "Tổng số: 0";
    const classCounts: { [key: string]: number } = {};
    for (const student of students) {
        const className = String(student['HẠNG GPLX'] || 'Khác').trim();
        classCounts[className] = (classCounts[className] || 0) + 1;
    }
    const sortedClasses = Object.keys(classCounts).sort();
    const parts = sortedClasses.map(className => `Hạng ${className}: ${classCounts[className]}`);
    return `Tổng số: ${students.length}\u00A0\u00A0\u00A0\u00A0${parts.join('; ')}`;
};

export const generateGhiChu = (record: StudentRecord): string => {
    const maHocVien = (record['MÃ HỌC VIÊN'] || '').toString().trim();
    const isRetake = maHocVien.startsWith('2721') || maHocVien.startsWith('2722');

    let testsTaken = (record['NỘI DUNG THI'] || '').toString().trim().toUpperCase();
    testsTaken = testsTaken.replace(/Đ/g, 'D');

    if (isRetake) return `Thi lại nội dung: ${testsTaken}`;
    return `Thi lần đầu`;
};

export const identifyTrainingUnit = (studentId: string | number | undefined, units: TrainingUnit[] = []): string => {
    if (!studentId || !units || units.length === 0) return '';
    const sId = studentId.toString().trim();
    const sortedUnits = [...units].sort((a, b) => b.code.length - a.code.length);
    const matchedUnit = sortedUnits.find(u => sId.startsWith(u.code));
    return matchedUnit ? matchedUnit.name : '';
};

import type { AppData, LicenseClassData, StudentRecord } from '../types';
import { getResultStatus, isStudentAbsent, isStudentPassed } from './reportUtils';

export const normalizeRecord = (record: any): StudentRecord => {
    const normalized: any = {};
    const keyMap: {[key: string]: string} = {
        'HỌ VÀ TÊN': 'HỌ VÀ TÊN', 'HO VA TEN': 'HỌ VÀ TÊN', 'HỌ TÊN': 'HỌ VÀ TÊN', 'HOTEN': 'HỌ VÀ TÊN', 'TÊN HỌC VIÊN': 'HỌ VÀ TÊN',
        'SỐ BÁO DANH': 'SỐ BÁO DANH', 'SBD': 'SỐ BÁO DANH', 'SO BAO DANH': 'SỐ BÁO DANH',
        'MÃ HỌC VIÊN': 'MÃ HỌC VIÊN', 'MÃ HV': 'MÃ HỌC VIÊN', 'MA HOC VIEN': 'MÃ HỌC VIÊN', 'MAHV': 'MÃ HỌC VIÊN', 'MÃ DK': 'MÃ HỌC VIÊN',
        'HẠNG GPLX': 'HẠNG GPLX', 'HẠNG': 'HẠNG GPLX', 'HANG': 'HẠNG GPLX', 'HANG GPLX': 'HẠNG GPLX', 'HẠNG XE': 'HẠNG GPLX',
        'NỘI DUNG THI': 'NỘI DUNG THI', 'NOI DUNG THI': 'NỘI DUNG THI', 'ND THI': 'NỘI DUNG THI', 'MÔN THI': 'NỘI DUNG THI', 'NDSH': 'NỘI DUNG THI',
        'LÝ THUYẾT': 'LÝ THUYẾT', 'LY THUYET': 'LÝ THUYẾT', 'LT': 'LÝ THUYẾT', 'KQ LT': 'LÝ THUYẾT',
        'MÔ PHỎNG': 'MÔ PHỎNG', 'MO PHONG': 'MÔ PHỎNG', 'MP': 'MÔ PHỎNG', 'KQ MP': 'MÔ PHỎNG',
        'SA HÌNH': 'SA HÌNH', 'THỰC HÀNH TRONG HÌNH': 'SA HÌNH', 'SH': 'SA HÌNH', 'KQ SH': 'SA HÌNH',
        'ĐƯỜNG TRƯỜNG': 'ĐƯỜNG TRƯỜNG', 'THỰC HÀNH ĐƯỜNG TRƯỜNG': 'ĐƯỜNG TRƯỜNG', 'ĐT': 'ĐƯỜNG TRƯỜNG', 'DT': 'ĐƯỜNG TRƯỜNG', 'KQ ĐT': 'ĐƯỜNG TRƯỜNG',
        'NGÀY SINH': 'NGÀY SINH', 'NGAY SINH': 'NGÀY SINH',
        'SỐ CHỨNG MINH': 'SỐ CHỨNG MINH', 'CCCD': 'SỐ CHỨNG MINH', 'CMND': 'SỐ CHỨNG MINH',
        'NƠI CƯ TRÚ': 'NƠI CƯ TRÚ', 'ĐỊA CHỈ': 'NƠI CƯ TRÚ'
    };

    Object.keys(record).forEach(key => {
        const cleanKey = key.trim().toUpperCase().replace(/\s+/g, ' ');
        let mappedKey = keyMap[cleanKey];
        if (!mappedKey) {
            if (cleanKey.includes('LY THUYET') || cleanKey.includes('LÝ THUYẾT')) mappedKey = 'LÝ THUYẾT';
            else if (cleanKey.includes('MO PHONG') || cleanKey.includes('MÔ PHỎNG')) mappedKey = 'MÔ PHỎNG';
            else if (cleanKey.includes('SA HINH') || cleanKey.includes('SA HÌNH')) mappedKey = 'SA HÌNH';
            else if (cleanKey.includes('DUONG TRUONG') || cleanKey.includes('ĐƯỜNG TRƯỜNG')) mappedKey = 'ĐƯỜNG TRƯỜNG';
            else mappedKey = cleanKey;
        }
        normalized[mappedKey] = record[key];
    });
    return normalized as StudentRecord;
};

const createNewClassData = (className: string): LicenseClassData => ({
    class: className,
    totalApplications: 0,
    totalParticipants: 0,
    theory: { total: 0, pass: 0, fail: 0 },
    simulation: { total: 0, pass: 0, fail: 0 },
    practicalCourse: { total: 0, pass: 0, fail: 0 },
    onRoad: { total: 0, pass: 0, fail: 0 },
    finalPass: 0,
});

export const normalizeData = (rawRecords: any[]): StudentRecord[] => {
    return rawRecords.map(raw => {
        const record = normalizeRecord(raw);
        if (!record['NỘI DUNG THI']) {
             const parts: string[] = [];
             if (record['LÝ THUYẾT'] !== undefined && record['LÝ THUYẾT'] !== '') parts.push('L');
             if (record['MÔ PHỎNG'] !== undefined && record['MÔ PHỎNG'] !== '') parts.push('M');
             if (record['SA HÌNH'] !== undefined && record['SA HÌNH'] !== '') parts.push('H');
             if (record['ĐƯỜNG TRƯỜNG'] !== undefined && record['ĐƯỜNG TRƯỜNG'] !== '') parts.push('Đ');
             if (parts.length > 0) record['NỘI DUNG THI'] = parts.join('+');
        }
        return record;
    });
};

export const processExcelData = (rawRecords: StudentRecord[]): AppData => {
    const records = normalizeData(rawRecords);
    const firstTimeData: { [className: string]: LicenseClassData } = {};
    const retakeData: { [className: string]: LicenseClassData } = {};

    for (const record of records) {
        const className = record['HẠNG GPLX']?.toString().trim();
        if (!className) continue;

        const maHocVien = (record['MÃ HỌC VIÊN'] || '').toString().trim();
        const isRetake = maHocVien.startsWith('2721') || maHocVien.startsWith('2722');
        const targetData = isRetake ? retakeData : firstTimeData;

        if (!targetData[className]) targetData[className] = createNewClassData(className);
        const classData = targetData[className];

        classData.totalApplications += 1;
        if (!isStudentAbsent(record)) classData.totalParticipants += 1;

        const theoryRes = getResultStatus(record['LÝ THUYẾT']);
        if (theoryRes.participated) {
            classData.theory.total += 1;
            if (theoryRes.passed) classData.theory.pass += 1;
        }
        const simRes = getResultStatus(record['MÔ PHỎNG']);
        if (simRes.participated) {
            classData.simulation.total += 1;
            if (simRes.passed) classData.simulation.pass += 1;
        }
        const practicalRes = getResultStatus(record['SA HÌNH']);
        if (practicalRes.participated) {
            classData.practicalCourse.total += 1;
            if (practicalRes.passed) classData.practicalCourse.pass += 1;
        }
        const onRoadRes = getResultStatus(record['ĐƯỜNG TRƯỜNG']);
        if (onRoadRes.participated) {
            classData.onRoad.total += 1;
            if (onRoadRes.passed) classData.onRoad.pass += 1;
        }
        if (isStudentPassed(record)) classData.finalPass += 1;
    }

    const finalizeData = (data: { [className: string]: LicenseClassData }): LicenseClassData[] => {
        const arr = Object.values(data);
        for (const cd of arr) {
            cd.theory.fail = cd.theory.total - cd.theory.pass;
            cd.simulation.fail = cd.simulation.total - cd.simulation.pass;
            cd.practicalCourse.fail = cd.practicalCourse.total - cd.practicalCourse.pass;
            cd.onRoad.fail = cd.onRoad.total - cd.onRoad.pass;
        }
        return arr.sort((a, b) => a.class.localeCompare(b.class));
    };

    return {
        firstTime: { title: 'a) Học viên dự thi lần đầu:', rows: finalizeData(firstTimeData) },
        retake: { title: 'b) Thí sinh thuộc đối tượng cấp lại giấy phép lái xe và thí sinh tự do:', rows: finalizeData(retakeData) }
    };
};

import React, { useState, useMemo, useEffect } from 'react';
import { DataInputPage } from './components/DataInputPage';
import { ReportDashboardPage } from './components/reports/ReportDashboardPage';
import { AdminSidebar } from './components/admin/AdminSidebar';
import { SessionList } from './components/admin/SessionList';
import { SettingsPage } from './components/admin/SettingsPage';
import { TrainingUnitManager } from './components/admin/TrainingUnitManager';
import { AggregateReportPage } from './components/admin/AggregateReportPage';
import { StudentLookupPage } from './components/admin/StudentLookupPage';
import { storageService } from './services/storageService';
import type { AppData, LicenseClassData, StudentRecord, ReportMetadata, SavedSession, TrainingUnit } from './types';
import { processExcelData, normalizeData } from './services/excelProcessor';
import { Toast } from './components/ui/Toast';

type AppView = 'dashboard' | 'create' | 'detail' | 'settings' | 'training-units' | 'aggregate-report' | 'student-lookup';

const App: React.FC = () => {
    const [currentView, setCurrentView] = useState<AppView>('dashboard');
    const [savedSessions, setSavedSessions] = useState<SavedSession[]>([]);
    const [appData, setAppData] = useState<AppData | null>(null);
    const [studentRecords, setStudentRecords] = useState<StudentRecord[] | null>(null);
    const [selectedSession, setSelectedSession] = useState<SavedSession | null>(null);
    const [trainingUnits, setTrainingUnits] = useState<TrainingUnit[]>([]);
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);
    const [darkMode, setDarkMode] = useState<boolean>(() => localStorage.getItem('theme') === 'dark');

    useEffect(() => {
        if (darkMode) {
            document.documentElement.classList.add('dark');
            localStorage.setItem('theme', 'dark');
        } else {
            document.documentElement.classList.remove('dark');
            localStorage.setItem('theme', 'light');
        }
    }, [darkMode]);

    const [reportMetadata, setReportMetadata] = useState<ReportMetadata>({
        meetingTime: '18 giờ 00 phút',
        meetingLocation: 'Trung tâm dạy nghề và Sát hạch lái xe Đông Đô',
        organizer: 'Giám đốc Công an tỉnh',
        attendees: [
            { id: '1', name: 'Đồng chí: Trung tá Dương Kim Giang', role: 'Phó Trưởng phòng, Chủ tịch Hội đồng' },
            { id: '2', name: 'Đồng chí: Trung tá Trần Duy Giang', role: 'Đội trưởng, Phó Chủ tịch Hội đồng' },
            { id: '3', name: 'Ông: Vũ Tiến Tuế', role: 'Giám đốc Trung tâm sát hạch, Ủy viên' },
            { id: '4', name: 'Đồng chí: Vương Mai Phương', role: 'Thư ký' },
        ],
        technicalErrorSBD: '',
    });

    const loadData = async () => {
        const sessions = await storageService.getAllSessions();
        const units = await storageService.getAllTrainingUnits();
        setSavedSessions(sessions);
        setTrainingUnits(units);
    };

    const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => setToast({ message, type });

    useEffect(() => {
        loadData();
    }, []);

    const handleExcelSubmit = (rawRecords: StudentRecord[]) => {
        setIsLoading(true);
        setError(null);
        try {
            const cleanRecords = normalizeData(rawRecords);
            const processedData = processExcelData(cleanRecords);
            setStudentRecords(cleanRecords);
            setAppData(processedData);
            showToast('Xử lý dữ liệu thành công!', 'info');
        } catch (e) {
             setError(`Lỗi xử lý file Excel: ${(e as Error).message}`);
             showToast('Lỗi xử lý file Excel', 'error');
        } finally {
            setIsLoading(false);
        }
    };

    const grandTotal = useMemo<LicenseClassData | null>(() => {
        if (!appData) return null;
        const allRows = [...appData.firstTime.rows, ...appData.retake.rows];
        if (allRows.length === 0) return null;
        return allRows.reduce((acc, row) => {
            acc.totalApplications += row.totalApplications;
            acc.totalParticipants += row.totalParticipants;
            acc.theory.total += row.theory.total; acc.theory.pass += row.theory.pass; acc.theory.fail += row.theory.fail;
            acc.simulation.total += row.simulation.total; acc.simulation.pass += row.simulation.pass; acc.simulation.fail += row.simulation.fail;
            acc.practicalCourse.total += row.practicalCourse.total; acc.practicalCourse.pass += row.practicalCourse.pass; acc.practicalCourse.fail += row.practicalCourse.fail;
            acc.onRoad.total += row.onRoad.total; acc.onRoad.pass += row.onRoad.pass; acc.onRoad.fail += row.onRoad.fail;
            acc.finalPass += row.finalPass;
            return acc;
        }, {
            class: 'a+b', totalApplications: 0, totalParticipants: 0,
            theory: { total: 0, pass: 0, fail: 0 }, simulation: { total: 0, pass: 0, fail: 0 },
            practicalCourse: { total: 0, pass: 0, fail: 0 }, onRoad: { total: 0, pass: 0, fail: 0 },
            finalPass: 0,
        });
    }, [appData]);

    const handleSaveSession = async (name: string, reportDate: Date) => {
        if (!appData || !grandTotal || !studentRecords) return;
        setIsLoading(true);
        try {
            const newSession: SavedSession = {
                id: Date.now().toString(), name, createdAt: Date.now(),
                reportDate: reportDate.toISOString(), studentRecords, appData,
                grandTotal, reportMetadata, trainingUnits
            };
            await storageService.saveSession(newSession);
            await loadData();
            setAppData(null); setStudentRecords(null);
            setCurrentView('dashboard');
            showToast('Đã lưu kỳ sát hạch thành công!', 'success');
        } catch (err) {
            showToast('Lỗi khi lưu dữ liệu!', 'error');
        } finally {
            setIsLoading(false);
        }
    };

    const handleSelectSession = async (session: SavedSession) => {
        setIsLoading(true);
        let fullSession = await storageService.getSessionById(session.id) || session;
        setSelectedSession(fullSession);
        setAppData(fullSession.appData);
        setStudentRecords(fullSession.studentRecords);
        setReportMetadata(fullSession.reportMetadata);
        setTrainingUnits(fullSession.trainingUnits || []);
        setCurrentView('detail');
        setIsLoading(false);
    };

    return (
        <div className={`flex h-screen bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-200 font-sans overflow-hidden ${darkMode ? 'dark' : ''}`}>
            <AdminSidebar currentView={currentView === 'detail' ? 'dashboard' : currentView} onChangeView={setCurrentView} darkMode={darkMode} onToggleDarkMode={() => setDarkMode(!darkMode)} />
            <main className="flex-1 h-full relative flex flex-col min-w-0">
                {currentView === 'dashboard' && <SessionList sessions={savedSessions} onSelectSession={handleSelectSession} onDeleteSession={async id => { await storageService.deleteSession(id); loadData(); }} onCreateNew={() => setCurrentView('create')} onRefresh={loadData} />}
                {currentView === 'create' && (
                    appData ? <ReportDashboardPage summaryData={appData} studentRecords={studentRecords} grandTotal={grandTotal} reportMetadata={reportMetadata} mode="preview" onSaveSession={handleSaveSession} trainingUnits={trainingUnits} />
                    : <DataInputPage onExcelSubmit={handleExcelSubmit} isLoading={isLoading} error={error} onClearData={() => setAppData(null)} reportMetadata={reportMetadata} onMetadataChange={setReportMetadata} />
                )}
                {currentView === 'detail' && selectedSession && appData && <ReportDashboardPage summaryData={appData} studentRecords={studentRecords} grandTotal={grandTotal} reportMetadata={reportMetadata} mode="view" initialReportDate={selectedSession.reportDate} sessionName={selectedSession.name} trainingUnits={trainingUnits} />}
                {currentView === 'aggregate-report' && <AggregateReportPage />}
                {currentView === 'student-lookup' && <StudentLookupPage />}
                {currentView === 'training-units' && <TrainingUnitManager trainingUnits={trainingUnits} onUnitsImport={units => { setTrainingUnits(units); loadData(); }} />}
                {currentView === 'settings' && <SettingsPage />}
            </main>
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        </div>
    );
};

export default App;

