import React, { useMemo, useState } from 'react';
import type { SavedSession, ConflictWarning } from '../../types';
import { getResultStatus } from '../../services/reportUtils';

interface ConflictAuditPageProps {
    sessions: SavedSession[];
}

interface AuditFinding extends ConflictWarning {
    currentSessionName: string;
    currentDate: string;
}

export const ConflictAuditPage: React.FC<ConflictAuditPageProps> = ({ sessions }) => {
    const [searchTerm, setSearchTerm] = useState('');

    const auditFindings = useMemo(() => {
        const findings: AuditFinding[] = [];
        if (sessions.length < 2) return [];

        // Sắp xếp các kỳ thi theo thời gian tăng dần
        const sortedSessions = [...sessions].sort((a, b) => 
            new Date(a.reportDate).getTime() - new Date(b.reportDate).getTime()
        );

        // Bản đồ lưu trữ các phần đã Đạt của mỗi học viên
        // Key: studentId, Value: { part, sessionName, date }
        const passedDatabase = new Map<string, { part: string, sessionName: string, date: string }[]>();

        sortedSessions.forEach(session => {
            const sessionDateStr = new Date(session.reportDate).toLocaleDateString('vi-VN');

            session.studentRecords.forEach(record => {
                const sid = String(record['MÃ HỌC VIÊN'] || '').trim();
                if (!sid) return;

                const currentND = String(record['NỘI DUNG THI'] || '').toUpperCase().replace(/Đ/g, 'D');

                // 1. Kiểm tra xem nội dung thi hiện tại có phần nào đã Đạt trong quá khứ không
                const history = passedDatabase.get(sid);
                if (history) {
                    ['L', 'M', 'H', 'D'].forEach(part => {
                        if (currentND.includes(part)) {
                            const prevPass = history.find(h => h.part === part);
                            if (prevPass) {
                                findings.push({
                                    studentName: record['HỌ VÀ TÊN'],
                                    studentId: sid,
                                    conflictPart: part === 'D' ? 'Đường trường' : (part === 'L' ? 'Lý thuyết' : (part === 'M' ? 'Mô phỏng' : 'Sa hình')),
                                    previousSessionName: prevPass.sessionName,
                                    previousDate: prevPass.date,
                                    currentSessionName: session.name,
                                    currentDate: sessionDateStr
                                });
                            }
                        }
                    });
                }

                // 2. Cập nhật các phần Đạt của kỳ này vào Database để kiểm tra cho các kỳ tương lai
                const results = [
                    { part: 'L', passed: getResultStatus(record['LÝ THUYẾT']).passed },
                    { part: 'M', passed: getResultStatus(record['MÔ PHỎNG']).passed },
                    { part: 'H', passed: getResultStatus(record['SA HÌNH']).passed },
                    { part: 'D', passed: getResultStatus(record['ĐƯỜNG TRƯỜNG']).passed },
                ];

                results.forEach(res => {
                    if (res.passed) {
                        const existing = passedHistoryForStudent(sid, passedDatabase);
                        // Chỉ thêm nếu phần này chưa có trong lịch sử (để lấy kỳ đạt đầu tiên)
                        if (!existing.some(e => e.part === res.part)) {
                            existing.push({ part: res.part, sessionName: session.name, date: sessionDateStr });
                            passedDatabase.set(sid, existing);
                        }
                    }
                });
            });
        });

        return findings.reverse(); // Đưa các cảnh báo mới nhất lên đầu
    }, [sessions]);

    const passedHistoryForStudent = (sid: string, db: Map<string, any[]>) => db.get(sid) || [];

    const filteredFindings = auditFindings.filter(f => 
        f.studentName.toLowerCase().includes(searchTerm.toLowerCase()) || 
        f.studentId.includes(searchTerm) ||
        f.currentSessionName.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="p-6 md:p-10 h-full overflow-y-auto bg-gray-50 dark:bg-gray-900 transition-colors">
            <div className="mb-8">
                <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Kiểm toán Nội dung thi</h2>
                <p className="text-gray-500 dark:text-gray-400 mt-1">Phát hiện các trường hợp thí sinh đăng ký thi lại những môn đã có kết quả "ĐẠT" trong lịch sử.</p>
            </div>

            <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden">
                <div className="p-4 border-b border-gray-100 dark:border-gray-700 flex items-center justify-between bg-gray-50 dark:bg-gray-750">
                    <div className="relative flex-1 max-w-md">
                        <i className="fa-solid fa-magnifying-glass absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"></i>
                        <input 
                            type="text" 
                            placeholder="Tìm học viên, mã HV hoặc kỳ thi..." 
                            className="w-full pl-10 pr-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm dark:bg-gray-700 dark:text-white"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                    <div className="text-xs text-gray-500 font-medium">
                        Tổng số nghi vấn: <span className="text-orange-600 font-bold">{filteredFindings.length}</span>
                    </div>
                </div>

                {filteredFindings.length === 0 ? (
                    <div className="p-20 text-center">
                        <div className="w-20 h-20 bg-green-50 dark:bg-green-900/20 rounded-full flex items-center justify-center mx-auto mb-4">
                            <i className="fa-solid fa-circle-check text-4xl text-green-500"></i>
                        </div>
                        <h3 className="text-lg font-bold text-gray-800 dark:text-white">Dữ liệu an toàn!</h3>
                        <p className="text-gray-500 dark:text-gray-400 mt-1">Không phát hiện học viên nào thi trùng nội dung đã đạt.</p>
                    </div>
                ) : (
                    <div className="overflow-x-auto">
                        <table className="w-full text-left text-sm">
                            <thead className="bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-200 uppercase font-bold text-[10px] tracking-wider">
                                <tr>
                                    <th className="px-6 py-4">Học viên</th>
                                    <th className="px-6 py-4 text-center">Môn nghi vấn</th>
                                    <th className="px-6 py-4">Kỳ thi Đã đạt</th>
                                    <th className="px-6 py-4">Kỳ thi Bị trùng (Hiện tại)</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                                {filteredFindings.map((finding, idx) => (
                                    <tr key={idx} className="hover:bg-orange-50 dark:hover:bg-orange-900/10 transition-colors">
                                        <td className="px-6 py-4">
                                            <div className="font-bold text-gray-900 dark:text-white">{finding.studentName}</div>
                                            <div className="text-xs text-gray-500 font-mono">Mã: {finding.studentId}</div>
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            <span className="px-3 py-1 bg-orange-100 dark:bg-orange-900/40 text-orange-700 dark:text-orange-300 rounded-full text-[11px] font-bold border border-orange-200 dark:border-orange-800">
                                                {finding.conflictPart}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="text-sm font-medium text-green-700 dark:text-green-400">{finding.previousSessionName}</div>
                                            <div className="text-xs text-gray-400">{finding.previousDate}</div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="text-sm font-medium text-red-600 dark:text-red-400">{finding.currentSessionName}</div>
                                            <div className="text-xs text-gray-400">{finding.currentDate}</div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            <div className="mt-6 p-4 bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-800 rounded-lg text-sm text-blue-700 dark:text-blue-300 flex items-start gap-3">
                <i className="fa-solid fa-circle-info mt-0.5"></i>
                <div>
