import React, { useMemo, useState } from 'react';
import type { SavedSession, ConflictWarning, StudentRecord } from '../../types';
import { getResultStatus, checkHistoricalConflicts } from '../../services/reportUtils';
import { normalizeData } from '../../services/excelProcessor';

declare const XLSX: any;

interface ConflictAuditPageProps {
    sessions: SavedSession[];
}

interface AuditFinding extends ConflictWarning {
    currentSessionName: string;
    currentDate: string;
}

export const ConflictAuditPage: React.FC<ConflictAuditPageProps> = ({ sessions }) => {
    const [activeTab, setActiveTab] = useState<'upload' | 'history'>('upload');
    const [searchTerm, setSearchTerm] = useState('');
    const [isProcessing, setIsProcessing] = useState(false);
    const [uploadedConflicts, setUploadedConflicts] = useState<ConflictWarning[]>([]);
    const [hasChecked, setHasChecked] = useState(false);

    // Tính toán kiểm toán toàn bộ lịch sử hệ thống (Tab History)
    const historyFindings = useMemo(() => {
        const findings: AuditFinding[] = [];
        if (sessions.length < 2) return [];

        const sortedSessions = [...sessions].sort((a, b) => 
            new Date(a.reportDate).getTime() - new Date(b.reportDate).getTime()
        );

        const passedDatabase = new Map<string, { part: string, sessionName: string, date: string }[]>();

        sortedSessions.forEach(session => {
            const sessionDateStr = new Date(session.reportDate).toLocaleDateString('vi-VN');

            session.studentRecords.forEach(record => {
                const sid = String(record['MÃ HỌC VIÊN'] || '').trim();
                if (!sid) return;

                const currentND = String(record['NỘI DUNG THI'] || '').toUpperCase().replace(/Đ/g, 'D');

                const history = passedDatabase.get(sid);
                if (history) {
                    ['L', 'M', 'H', 'D'].forEach(part => {
                        if (currentND.includes(part)) {
                            const prevPass = history.find(h => h.part === part);
                            if (prevPass) {
                                findings.push({
                                    studentName: record['HỌ VÀ TÊN'],
                                    studentId: sid,
                                    conflictPart: part === 'D' ? 'Đường trường' : (part === 'L' ? 'Lý thuyết' : (part === 'M' ? 'Mô phỏng' : 'Sa hình')),
                                    previousSessionName: prevPass.sessionName,
                                    previousDate: prevPass.date,
                                    currentSessionName: session.name,
                                    currentDate: sessionDateStr
                                });
                            }
                        }
                    });
                }

                const results = [
                    { part: 'L', passed: getResultStatus(record['LÝ THUYẾT']).passed },
                    { part: 'M', passed: getResultStatus(record['MÔ PHỎNG']).passed },
                    { part: 'H', passed: getResultStatus(record['SA HÌNH']).passed },
                    { part: 'D', passed: getResultStatus(record['ĐƯỜNG TRƯỜNG']).passed },
                ];

                results.forEach(res => {
                    if (res.passed) {
                        const existing = passedDatabase.get(sid) || [];
                        if (!existing.some(e => e.part === res.part)) {
                            existing.push({ part: res.part, sessionName: session.name, date: sessionDateStr });
                            passedDatabase.set(sid, existing);
                        }
                    }
                });
            });
        });

        return findings.reverse();
    }, [sessions]);

    // Xử lý upload file để kiểm tra
    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setIsProcessing(true);
            setHasChecked(false);
            const file = e.target.files[0];
            const reader = new FileReader();

            reader.onload = (event) => {
                try {
                    const data = new Uint8Array(event.target!.result as ArrayBuffer);
                    const workbook = XLSX.read(data, { type: 'array' });
                    const sheetName = workbook.SheetNames[0];
                    const worksheet = workbook.Sheets[sheetName];
                    const json: any[] = XLSX.utils.sheet_to_json(worksheet);

                    const normalized = normalizeData(json);
                    const conflicts = checkHistoricalConflicts(normalized, sessions);

                    setUploadedConflicts(conflicts);
                    setHasChecked(true);
                } catch (err) {
                    console.error("Lỗi xử lý file:", err);
                    alert("Có lỗi xảy ra khi đọc file Excel.");
                } finally {
                    setIsProcessing(false);
                    e.target.value = ''; // Reset input
                }
            };
            reader.readAsArrayBuffer(file);
        }
    };

    const filteredHistory = historyFindings.filter(f => 
        f.studentName.toLowerCase().includes(searchTerm.toLowerCase()) || 
        f.studentId.includes(searchTerm)
    );

    return (
        <div className="p-6 md:p-10 h-full overflow-y-auto bg-gray-50 dark:bg-gray-900 transition-colors">
            <div className="mb-6">
                <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Kiểm toán Nội dung thi</h2>
                <p className="text-gray-500 dark:text-gray-400 mt-1">Phát hiện các sai sót trong việc đăng ký nội dung thi dựa trên lịch sử dữ liệu.</p>
            </div>

            {/* Tabs Navigation */}
            <div className="flex gap-1 bg-gray-200 dark:bg-gray-800 p-1 rounded-xl w-fit mb-6">
                <button 
                    onClick={() => setActiveTab('upload')}
                    className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'upload' ? 'bg-white dark:bg-gray-700 text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}
                >
                    <i className="fa-solid fa-file-import mr-2"></i> Kiểm tra File mới
                </button>
                <button 
                    onClick={() => setActiveTab('history')}
                    className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'history' ? 'bg-white dark:bg-gray-700 text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}
                >
