                </div>
            </div>

            {/* Report Content */}
            <div className="report-content flex-1 p-8 bg-gray-50 dark:bg-gray-900 overflow-y-auto print:p-0 print:bg-white">
                 <div className="max-w-[297mm] mx-auto bg-white shadow-lg p-10 min-h-[210mm] print:shadow-none print:p-0 transition-colors">
                    {renderActiveReport()}
                 </div>
            </div>

            {/* Metadata Modal */}
            {isMetadataModalOpen && (
                <ReportMetadataModal
                    initialMetadata={localMetadata}
                    onSave={(newMetadata) => {
                        setLocalMetadata(newMetadata);
                        setIsMetadataModalOpen(false);
                    }}
                    onClose={() => setIsMetadataModalOpen(false)}
                />
            )}
        </div>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { DataInputPage } from './components/DataInputPage';
import { ReportDashboardPage } from './components/reports/ReportDashboardPage';
import { AdminSidebar } from './components/admin/AdminSidebar';
import { SessionList } from './components/admin/SessionList';
import { SettingsPage } from './components/admin/SettingsPage';
import { TrainingUnitManager } from './components/admin/TrainingUnitManager';
import { AggregateReportPage } from './components/admin/AggregateReportPage';
import { StudentLookupPage } from './components/admin/StudentLookupPage';
import { ConflictAuditPage } from './components/admin/ConflictAuditPage';
import { storageService } from './services/storageService';
import type { AppData, LicenseClassData, StudentRecord, ReportMetadata, SavedSession, TrainingUnit, ConflictWarning } from './types';
import { processExcelData, normalizeData } from './services/excelProcessor';
import { checkHistoricalConflicts } from './services/reportUtils';
import { Toast } from './components/ui/Toast';

type AppView = 'dashboard' | 'create' | 'detail' | 'settings' | 'training-units' | 'aggregate-report' | 'student-lookup' | 'conflict-audit';

const App: React.FC = () => {
    const [currentView, setCurrentView] = useState<AppView>('dashboard');
    const [savedSessions, setSavedSessions] = useState<SavedSession[]>([]);
    const [appData, setAppData] = useState<AppData | null>(null);
    const [studentRecords, setStudentRecords] = useState<StudentRecord[] | null>(null);
    const [selectedSession, setSelectedSession] = useState<SavedSession | null>(null);
    const [trainingUnits, setTrainingUnits] = useState<TrainingUnit[]>([]);
    const [conflicts, setConflicts] = useState<ConflictWarning[]>([]);
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);
    const [darkMode, setDarkMode] = useState<boolean>(() => localStorage.getItem('theme') === 'dark');

    useEffect(() => {
        if (darkMode) {
            document.documentElement.classList.add('dark');
            localStorage.setItem('theme', 'dark');
        } else {
            document.documentElement.classList.remove('dark');
            localStorage.setItem('theme', 'light');
        }
    }, [darkMode]);

    const [reportMetadata, setReportMetadata] = useState<ReportMetadata>({
        meetingTime: '18 giờ 00 phút',
        meetingLocation: 'Trung tâm dạy nghề và Sát hạch lái xe Đông Đô',
        organizer: 'Giám đốc Công an tỉnh',
        attendees: [
            { id: '1', name: 'Đồng chí: Trung tá Dương Kim Giang', role: 'Phó Trưởng phòng, Chủ tịch Hội đồng' },
            { id: '2', name: 'Đồng chí: Trung tá Trần Duy Giang', role: 'Đội trưởng, Phó Chủ tịch Hội đồng' },
            { id: '3', name: 'Ông: Vũ Tiến Tuế', role: 'Giám đốc Trung tâm sát hạch, Ủy viên' },
            { id: '4', name: 'Đồng chí: Vương Mai Phương', role: 'Thư ký' },
        ],
        technicalErrorSBD: '',
    });

    const loadData = async () => {
        const [sessions, units] = await Promise.all([
            storageService.getAllSessions(),
            storageService.getAllTrainingUnits()
        ]);
        setSavedSessions(sessions);
        setTrainingUnits(units);
    };

    const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => setToast({ message, type });

    useEffect(() => {
        loadData();
    }, []);

    const handleExcelSubmit = (rawRecords: StudentRecord[]) => {
        setIsLoading(true);
        setError(null);
        setConflicts([]);
        try {
            const cleanRecords = normalizeData(rawRecords);
            const processedData = processExcelData(cleanRecords);
            const detectedConflicts = checkHistoricalConflicts(cleanRecords, savedSessions);
            setConflicts(detectedConflicts);
            setStudentRecords(cleanRecords);
            setAppData(processedData);
            if (detectedConflicts.length > 0) {
                showToast(`Phát hiện ${detectedConflicts.length} thí sinh đã đạt môn này trước đó!`, 'info');
            } else {
                showToast('Xử lý dữ liệu thành công!', 'info');
            }
        } catch (e) {
             setError(`Lỗi xử lý file Excel: ${(e as Error).message}`);
             showToast('Lỗi xử lý file Excel', 'error');
        } finally {
            setIsLoading(false);
        }
    };

    const grandTotal = useMemo<LicenseClassData | null>(() => {
        if (!appData) return null;
        const allRows = [...appData.firstTime.rows, ...appData.retake.rows];
        if (allRows.length === 0) return null;
        return allRows.reduce((acc, row) => {
            acc.totalApplications += row.totalApplications;
            acc.totalParticipants += row.totalParticipants;
            acc.theory.total += row.theory.total; acc.theory.pass += row.theory.pass; acc.theory.fail += row.theory.fail;
            acc.simulation.total += row.simulation.total; acc.simulation.pass += row.simulation.pass; acc.simulation.fail += row.simulation.fail;
            acc.practicalCourse.total += row.practicalCourse.total; acc.practicalCourse.pass += row.practicalCourse.pass; acc.practicalCourse.fail += row.practicalCourse.fail;
            acc.onRoad.total += row.onRoad.total; acc.onRoad.pass += row.onRoad.pass; acc.onRoad.fail += row.onRoad.fail;
            acc.finalPass += row.finalPass;
            return acc;
        }, {
            class: 'a+b', totalApplications: 0, totalParticipants: 0,
            theory: { total: 0, pass: 0, fail: 0 }, simulation: { total: 0, pass: 0, fail: 0 },
            practicalCourse: { total: 0, pass: 0, fail: 0 }, onRoad: { total: 0, pass: 0, fail: 0 },
            finalPass: 0,
        });
    }, [appData]);

    const handleSaveSession = async (name: string, reportDate: Date) => {
        if (!appData || !grandTotal || !studentRecords) {
            showToast('Không có dữ liệu để lưu!', 'error');
            return;
        }
        setIsLoading(true);
        try {
            const newSession: SavedSession = {
                id: Date.now().toString(), 
                name: name.trim() || `Kỳ sát hạch ${reportDate.toLocaleDateString('vi-VN')}`, 
                createdAt: Date.now(),
                reportDate: reportDate.toISOString(), 
                studentRecords, 
                appData,
                grandTotal, 
                reportMetadata, 
                trainingUnits
            };
            await storageService.saveSession(newSession);
            await loadData();
            setAppData(null); 
            setStudentRecords(null); 
            setConflicts([]);
            setCurrentView('dashboard');
            showToast('Đã lưu kỳ sát hạch thành công!', 'success');
        } catch (err) {
            console.error("Save Error:", err);
            showToast(`Lỗi khi lưu dữ liệu: ${(err as Error).message}`, 'error');
        } finally {
            setIsLoading(false);
        }
    };

    const handleSelectSession = async (session: SavedSession) => {
        setIsLoading(true);
        try {
            let fullSession = await storageService.getSessionById(session.id);
            if (!fullSession) fullSession = session;
            setSelectedSession(fullSession);
            setAppData(fullSession.appData);
            setStudentRecords(fullSession.studentRecords);
            setReportMetadata(fullSession.reportMetadata);
            setTrainingUnits(fullSession.trainingUnits || []);
            setConflicts([]);
            setCurrentView('detail');
        } catch (err) {
            showToast('Lỗi tải thông tin kỳ sát hạch', 'error');
        } finally {
            setIsLoading(false);
        }
    };

    const handleStudentUpdate = (id: string, field: string, value: any) => {
        if (!studentRecords) return;
        const newRecords = studentRecords.map(r => {
            if (String(r['SỐ BÁO DANH']) === id) {
                return { ...r, [field]: value };
            }
            return r;
        });
        const reprocessedData = processExcelData(newRecords);
        setStudentRecords(newRecords);
        setAppData(reprocessedData);
        showToast('Đã cập nhật dữ liệu thí sinh', 'info');
    };

    return (
        <div className={`flex h-screen bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-200 font-sans overflow-hidden transition-colors duration-200 ${darkMode ? 'dark' : ''}`}>
            <AdminSidebar 
                currentView={currentView === 'detail' ? 'dashboard' : currentView} 
                onChangeView={(v) => {
                    if (v === 'create') { setAppData(null); setStudentRecords(null); setConflicts([]); }
                    setCurrentView(v);
                }} 
                darkMode={darkMode} 
                onToggleDarkMode={() => setDarkMode(!darkMode)} 
            />
            <main className="flex-1 h-full relative flex flex-col min-w-0">
                {currentView === 'dashboard' && <SessionList sessions={savedSessions} onSelectSession={handleSelectSession} onDeleteSession={async id => { await storageService.deleteSession(id); loadData(); }} onCreateNew={() => setCurrentView('create')} onRefresh={loadData} />}
                {currentView === 'create' && (
                    appData ? <ReportDashboardPage summaryData={appData} studentRecords={studentRecords} grandTotal={grandTotal} reportMetadata={reportMetadata} mode="preview" onSaveSession={handleSaveSession} trainingUnits={trainingUnits} onStudentUpdate={handleStudentUpdate} isLoading={isLoading} />
                    : <DataInputPage onExcelSubmit={handleExcelSubmit} isLoading={isLoading} error={error} onClearData={() => { setAppData(null); setConflicts([]); }} reportMetadata={reportMetadata} onMetadataChange={setReportMetadata} conflicts={conflicts} />
                )}
                {currentView === 'detail' && selectedSession && appData && <ReportDashboardPage summaryData={appData} studentRecords={studentRecords} grandTotal={grandTotal} reportMetadata={reportMetadata} mode="view" initialReportDate={selectedSession.reportDate} sessionName={selectedSession.name} trainingUnits={trainingUnits} onStudentUpdate={handleStudentUpdate} isLoading={isLoading} onUpdateSession={async (name, date, meta) => {
                    const updated = { ...selectedSession, name, reportDate: date.toISOString(), reportMetadata: meta };
                    setIsLoading(true);
                    try {
                        await storageService.saveSession(updated);
                        await loadData();
                        showToast('Cập nhật kỳ sát hạch thành công', 'success');
                    } catch (err) {
                        showToast(`Lỗi: ${(err as Error).message}`, 'error');
                    } finally {
                        setIsLoading(false);
                    }
                }} />}
                {currentView === 'aggregate-report' && <AggregateReportPage />}
                {currentView === 'student-lookup' && <StudentLookupPage />}
                {currentView === 'conflict-audit' && <ConflictAuditPage sessions={savedSessions} />}
                {currentView === 'training-units' && <TrainingUnitManager trainingUnits={trainingUnits} onUnitsImport={units => { setTrainingUnits(units); loadData(); }} />}
                {currentView === 'settings' && <SettingsPage onRefresh={() => loadData()} />}
            </main>
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        </div>
    );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import type { SavedSession, StudentRecord } from '../../types';
import { storageService } from '../../services/storageService';
import { isStudentPassed, isStudentAbsent } from '../../services/reportUtils';

interface StudentExamHistory {
    studentName: string;
    studentId: string;
    cccd: string;
    licenseClass: string;
    attempts: {
        sessionName: string;
        reportDate: string;
        data: StudentRecord;
    }[];
}

export const StudentLookupPage: React.FC = () => {
    const [sessions, setSessions] = useState<SavedSession[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [selectedStudentHistory, setSelectedStudentHistory] = useState<StudentExamHistory | null>(null);

    // Filter States
    const [searchTerm, setSearchTerm] = useState('');
    const [dateFrom, setDateFrom] = useState('');
    const [dateTo, setDateTo] = useState('');
    const [selectedClass, setSelectedClass] = useState('all');
    const [selectedStatus, setSelectedStatus] = useState<'all' | 'passed' | 'failed' | 'absent'>('all');

    useEffect(() => {
        const loadData = async () => {
            setIsLoading(true);
            try {
                const data = await storageService.getAllSessions();
                setSessions(data);
            } catch (error) {
                console.error("Failed to load sessions", error);
            } finally {
                setIsLoading(false);
            }
        };
        loadData();
    }, []);

    const uniqueClasses = useMemo(() => {
        const classes = new Set<string>();
        sessions.forEach(session => {
            session.studentRecords?.forEach(s => {
                if (s['HẠNG GPLX']) classes.add(s['HẠNG GPLX'].toString().trim());
            });
        });
        return Array.from(classes).sort();
    }, [sessions]);

    // Grouping logic for Search Results
    const searchResults = useMemo(() => {
        if (sessions.length === 0) return [];

        const studentMap = new Map<string, StudentExamHistory>();
        const term = searchTerm.toLowerCase().trim();
        const fromDate = dateFrom ? new Date(dateFrom).getTime() : 0;
        const toDate = dateTo ? new Date(dateTo).getTime() + (86400000 - 1) : Infinity;

        sessions.forEach(session => {
            const sessionTime = new Date(session.reportDate).getTime();
            if (sessionTime < fromDate || sessionTime > toDate) return;

            session.studentRecords?.forEach(student => {
                const sid = (student['MÃ HỌC VIÊN'] || '').toString().trim();
                if (!sid) return;

                // Filter by Class & Status
                if (selectedClass !== 'all' && student['HẠNG GPLX'] !== selectedClass) return;

                const isAbsent = isStudentAbsent(student);
                const isPass = isStudentPassed(student);
                if (selectedStatus === 'passed' && !isPass) return;
                if (selectedStatus === 'absent' && !isAbsent) return;
                if (selectedStatus === 'failed' && (isPass || isAbsent)) return;

                // Filter by Search Term
                if (term) {
                    const name = (student['HỌ VÀ TÊN'] || '').toLowerCase();
                    const cccd = (student['SỐ CHỨNG MINH'] || '').toString().toLowerCase();
                    const sbd = (student['SỐ BÁO DANH'] || '').toString().toLowerCase();
                    if (!name.includes(term) && !sid.toLowerCase().includes(term) && !cccd.includes(term) && sbd !== term) return;
                }

                if (!studentMap.has(sid)) {
                    studentMap.set(sid, {
                        studentName: student['HỌ VÀ TÊN'],
                        studentId: sid,
                        cccd: (student['SỐ CHỨNG MINH'] || '').toString(),
                        licenseClass: student['HẠNG GPLX'],
                        attempts: []
                    });
                }

                studentMap.get(sid)!.attempts.push({
                    sessionName: session.name,
                    reportDate: session.reportDate,
                    data: student
                });
            });
        });

        const list = Array.from(studentMap.values());
        // Sort each student's attempts by date desc
        list.forEach(s => s.attempts.sort((a, b) => new Date(b.reportDate).getTime() - new Date(a.reportDate).getTime()));
        // Sort the list by the most recent exam date of each student
        return list.sort((a, b) => new Date(b.attempts[0].reportDate).getTime() - new Date(a.attempts[0].reportDate).getTime());
    }, [sessions, searchTerm, dateFrom, dateTo, selectedClass, selectedStatus]);

    const getScoreColor = (score: string | undefined) => {
        if (!score) return 'text-gray-300';
        const s = score.trim().toUpperCase();
        if (s === 'ĐẠT') return 'text-green-600 font-bold';
        if (s === 'KHÔNG ĐẠT' || s === 'TRƯỢT') return 'text-red-600 font-bold';
        return 'text-gray-800 font-medium';
    };

    return (
        <div className="p-6 md:p-8 h-full overflow-y-auto bg-gray-50 dark:bg-gray-900 transition-colors">
            <div className="mb-6">
                <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Tra cứu Hồ sơ Thí sinh</h2>
                <p className="text-gray-500 dark:text-gray-400 mt-1 text-sm">Tìm kiếm lịch sử và kết quả thi chi tiết qua các kỳ sát hạch.</p>
            </div>

            {/* Filter Panel */}
            <div className="bg-white dark:bg-gray-800 p-5 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 mb-6 space-y-4">
                <div className="flex flex-col md:flex-row gap-4">
                    <div className="flex-1 relative">
                        <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
                        <input 
                            type="text" 
                            className="w-full pl-11 pr-4 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all dark:bg-gray-700 dark:text-white"
                            placeholder="Tên, Mã HV, SBD hoặc CCCD..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                    {(searchTerm || dateFrom || dateTo || selectedClass !== 'all' || selectedStatus !== 'all') && (
                        <button 
                            onClick={() => { setSearchTerm(''); setDateFrom(''); setDateTo(''); setSelectedClass('all'); setSelectedStatus('all'); }}
                            className="px-4 py-2 text-red-600 bg-red-50 dark:bg-red-900/20 hover:bg-red-100 rounded-lg text-sm font-medium transition-colors flex items-center justify-center gap-2"
                        >
                            <i className="fa-solid fa-filter-circle-xmark"></i> Xóa lọc
                        </button>
                    )}
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                    <div className="flex items-center gap-2 bg-gray-50 dark:bg-gray-700 p-1 rounded-lg border dark:border-gray-600">
                        <input type="date" className="w-full bg-transparent border-none text-xs p-2 text-gray-600 dark:text-gray-300" value={dateFrom} onChange={(e) => setDateFrom(e.target.value)} title="Từ ngày" />
                        <span className="text-gray-400"><i className="fa-solid fa-arrow-right"></i></span>
                        <input type="date" className="w-full bg-transparent border-none text-xs p-2 text-gray-600 dark:text-gray-300" value={dateTo} onChange={(e) => setDateTo(e.target.value)} title="Đến ngày" />
                    </div>
                    <select className="px-3 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg text-sm dark:bg-gray-700 dark:text-white outline-none" value={selectedClass} onChange={(e) => setSelectedClass(e.target.value)}>
                        <option value="all">Tất cả Hạng</option>
                        {uniqueClasses.map(cls => <option key={cls} value={cls}>Hạng {cls}</option>)}
                    </select>
                    <select className="px-3 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg text-sm dark:bg-gray-700 dark:text-white outline-none" value={selectedStatus} onChange={(e) => setSelectedStatus(e.target.value as any)}>
                        <option value="all">Tất cả Trạng thái</option>
                        <option value="passed">Đạt</option>
                        <option value="failed">Trượt</option>
                        <option value="absent">Vắng thi</option>
                    </select>
                </div>
            </div>

            {isLoading ? (
                <div className="text-center py-20"><i className="fa-solid fa-spinner animate-spin text-3xl text-blue-500"></i></div>
            ) : (
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                    {searchResults.map((student, index) => {
                        const latest = student.attempts[0].data;
                        return (
                            <div key={index} className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 p-5 hover:border-blue-300 dark:hover:border-blue-500 transition-all group">
                                <div className="flex justify-between items-start mb-4">
                                    <div>
                                        <h3 className="text-lg font-bold text-gray-800 dark:text-white group-hover:text-blue-600 transition-colors">{student.studentName}</h3>
                                        <div className="text-sm text-gray-500 flex items-center gap-2 mt-1">
                                            <span className="font-mono bg-gray-100 dark:bg-gray-700 px-2 py-0.5 rounded text-xs">Mã: {student.studentId}</span>
                                            {student.cccd && <span className="font-mono bg-gray-100 dark:bg-gray-700 px-2 py-0.5 rounded text-xs">CCCD: {student.cccd}</span>}
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <div className="px-3 py-1 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-full text-xs font-bold border border-blue-100 dark:border-blue-800">
                                            {student.attempts.length} Lượt thi
                                        </div>
                                        <div className="text-[10px] text-gray-400 mt-2">Hạng: <span className="font-bold text-gray-600 dark:text-gray-300">{student.licenseClass}</span></div>
                                    </div>
                                </div>

                                <div className="bg-gray-50 dark:bg-gray-750 rounded-lg p-3 mb-4 grid grid-cols-4 gap-2 text-center text-xs">
                                    <div><div className="text-gray-400 font-bold mb-1 uppercase text-[10px]">Lý thuyết</div><div className={getScoreColor(latest['LÝ THUYẾT'])}>{latest['LÝ THUYẾT'] || '-'}</div></div>
                                    <div><div className="text-gray-400 font-bold mb-1 uppercase text-[10px]">Mô phỏng</div><div className={getScoreColor(latest['MÔ PHỎNG'])}>{latest['MÔ PHỎNG'] || '-'}</div></div>
                                    <div><div className="text-gray-400 font-bold mb-1 uppercase text-[10px]">Sa hình</div><div className={getScoreColor(latest['SA HÌNH'])}>{latest['SA HÌNH'] || '-'}</div></div>
                                    <div><div className="text-gray-400 font-bold mb-1 uppercase text-[10px]">Đ.Trường</div><div className={getScoreColor(latest['ĐƯỜNG TRƯỜNG'])}>{latest['ĐƯỜNG TRƯỜNG'] || '-'}</div></div>
                                </div>

                                <button 
                                    onClick={() => setSelectedStudentHistory(student)}
                                    className="w-full py-2 bg-white dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-lg text-sm font-bold text-blue-600 dark:text-blue-400 hover:bg-blue-600 hover:text-white dark:hover:bg-blue-600 dark:hover:text-white transition-all flex items-center justify-center gap-2"
                                >
                                    <i className="fa-solid fa-clock-rotate-left"></i> Xem chi tiết lịch sử
                                </button>
                            </div>
                        );
                    })}
                </div>
            )}

            {/* History Modal */}
            {selectedStudentHistory && (
                <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
                    <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl w-full max-w-4xl max-h-[90vh] flex flex-col overflow-hidden animate-slide-up">
                        <header className="p-6 border-b dark:border-gray-700 flex justify-between items-center bg-gray-50 dark:bg-gray-750">
                            <div>
                                <h2 className="text-xl font-bold text-gray-900 dark:text-white">Lịch sử thi: {selectedStudentHistory.studentName}</h2>
                                <p className="text-sm text-gray-500 mt-1">Mã học viên: {selectedStudentHistory.studentId} • Hạng: {selectedStudentHistory.licenseClass}</p>
                            </div>
                            <button onClick={() => setSelectedStudentHistory(null)} className="w-10 h-10 flex items-center justify-center text-gray-400 hover:text-gray-900 dark:hover:text-white rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-all">
                                <i className="fa-solid fa-xmark text-xl"></i>
                            </button>
                        </header>

                        <div className="flex-1 overflow-y-auto p-6 bg-white dark:bg-gray-800">
                            <div className="relative border-l-2 border-blue-200 dark:border-blue-900 ml-3 pl-8 space-y-8">
                                {selectedStudentHistory.attempts.map((attempt, idx) => {
                                    const isPass = isStudentPassed(attempt.data);
                                    const isAbs = isStudentAbsent(attempt.data);
                                    return (
                                        <div key={idx} className="relative">
                                            {/* Time dot */}
                                            <div className={`absolute -left-11 top-1 w-6 h-6 rounded-full border-4 border-white dark:border-gray-800 flex items-center justify-center shadow-sm ${
                                                isAbs ? 'bg-gray-400' : isPass ? 'bg-green-500' : 'bg-red-500'
                                            }`}>
                                                {isPass ? <i className="fa-solid fa-check text-[10px] text-white"></i> : <i className="fa-solid fa-xmark text-[10px] text-white"></i>}
                                            </div>

                                            <div className="bg-gray-50 dark:bg-gray-750 p-5 rounded-xl border border-gray-100 dark:border-gray-700 shadow-sm">
                                                <div className="flex justify-between items-start mb-4">
                                                    <div>
                                                        <h4 className="font-bold text-gray-800 dark:text-white">{attempt.sessionName}</h4>
                                                        <p className="text-xs text-gray-400 mt-0.5"><i className="fa-regular fa-calendar-check mr-1"></i>Ngày thi: {new Date(attempt.reportDate).toLocaleDateString('vi-VN')}</p>
                                                    </div>
                                                    <div className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${
                                                        isAbs ? 'bg-gray-200 text-gray-600' : isPass ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                                                    }`}>
                                                        {isAbs ? 'VẮNG' : isPass ? 'ĐẠT SÁT HẠCH' : 'KHÔNG ĐẠT'}
                                                    </div>
                                                </div>

                                                <div className="grid grid-cols-4 gap-4">
                                                    <div className="bg-white dark:bg-gray-800 p-3 rounded-lg border border-gray-100 dark:border-gray-600 text-center">
                                                        <div className="text-[10px] text-gray-400 font-bold uppercase mb-1">Lý thuyết</div>
                                                        <div className={`text-sm ${getScoreColor(attempt.data['LÝ THUYẾT'])}`}>{attempt.data['LÝ THUYẾT'] || 'N/A'}</div>
                                                    </div>
                                                    <div className="bg-white dark:bg-gray-800 p-3 rounded-lg border border-gray-100 dark:border-gray-600 text-center">
                                                        <div className="text-[10px] text-gray-400 font-bold uppercase mb-1">Mô phỏng</div>
                                                        <div className={`text-sm ${getScoreColor(attempt.data['MÔ PHỎNG'])}`}>{attempt.data['MÔ PHỎNG'] || 'N/A'}</div>
                                                    </div>
                                                    <div className="bg-white dark:bg-gray-800 p-3 rounded-lg border border-gray-100 dark:border-gray-600 text-center">
                                                        <div className="text-[10px] text-gray-400 font-bold uppercase mb-1">Sa hình</div>
                                                        <div className={`text-sm ${getScoreColor(attempt.data['SA HÌNH'])}`}>{attempt.data['SA HÌNH'] || 'N/A'}</div>
                                                    </div>
                                                    <div className="bg-white dark:bg-gray-800 p-3 rounded-lg border border-gray-100 dark:border-gray-600 text-center">
                                                        <div className="text-[10px] text-gray-400 font-bold uppercase mb-1">Đường trường</div>
                                                        <div className={`text-sm ${getScoreColor(attempt.data['ĐƯỜNG TRƯỜNG'])}`}>{attempt.data['ĐƯỜNG TRƯỜNG'] || 'N/A'}</div>
                                                    </div>
                                                </div>
                                                <div className="mt-3 text-[11px] text-gray-500">
                                                    <span className="font-bold">Nội dung đăng ký:</span> <span className="text-blue-600 dark:text-blue-400 font-mono">{attempt.data['NỘI DUNG THI'] || '---'}</span>
                                                    <span className="mx-2">•</span>
                                                    <span className="font-bold">SBD:</span> <span className="text-gray-700 dark:text-gray-300">{attempt.data['SỐ BÁO DANH']}</span>
                                                </div>
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>

                        <footer className="p-4 bg-gray-50 dark:bg-gray-750 border-t dark:border-gray-700 text-center">
                            <button onClick={() => setSelectedStudentHistory(null)} className="px-10 py-2.5 bg-gray-800 dark:bg-gray-600 text-white rounded-xl font-bold hover:bg-gray-900 transition-all">Đóng</button>
                        </footer>
                    </div>
                </div>
            )}

            <style dangerouslySetInnerHTML={{ __html: `
                .animate-fade-in { animation: fadeIn 0.2s ease-out; }
                .animate-slide-up { animation: slideUp 0.3s cubic-bezier(0.16, 1, 0.3, 1); }
                @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
                @keyframes slideUp { from { transform: translateY(20px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
            `}} />
        </div>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import type { SavedSession, StudentRecord } from '../../types';
import { storageService } from '../../services/storageService';
import { isStudentPassed, isStudentAbsent } from '../../services/reportUtils';

interface StudentExamHistory {
    studentName: string;
    identityKey: string; // CCCD hoặc Mã HV nếu không có CCCD
    cccd: string;
    licenseClass: string;
    associatedStudentIds: Set<string>; // Danh sách các Mã HV liên kết với người này
    attempts: {
        sessionName: string;
        reportDate: string;
        data: StudentRecord;
    }[];
}

export const StudentLookupPage: React.FC = () => {
    const [sessions, setSessions] = useState<SavedSession[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [selectedStudentHistory, setSelectedStudentHistory] = useState<StudentExamHistory | null>(null);

    // Filter States
    const [searchTerm, setSearchTerm] = useState('');
    const [dateFrom, setDateFrom] = useState('');
    const [dateTo, setDateTo] = useState('');
    const [selectedClass, setSelectedClass] = useState('all');
    const [selectedStatus, setSelectedStatus] = useState<'all' | 'passed' | 'failed' | 'absent'>('all');

    useEffect(() => {
        const loadData = async () => {
            setIsLoading(true);
            try {
                const data = await storageService.getAllSessions();
                setSessions(data);
            } catch (error) {
                console.error("Failed to load sessions", error);
            } finally {
                setIsLoading(false);
            }
        };
        loadData();
    }, []);

    const uniqueClasses = useMemo(() => {
        const classes = new Set<string>();
        sessions.forEach(session => {
            session.studentRecords?.forEach(s => {
                if (s['HẠNG GPLX']) classes.add(s['HẠNG GPLX'].toString().trim());
            });
        });
        return Array.from(classes).sort();
    }, [sessions]);

    // Grouping logic for Search Results
    const searchResults = useMemo(() => {
        if (sessions.length === 0) return [];

        const studentMap = new Map<string, StudentExamHistory>();
        const term = searchTerm.toLowerCase().trim();
        const fromDate = dateFrom ? new Date(dateFrom).getTime() : 0;
        const toDate = dateTo ? new Date(dateTo).getTime() + (86400000 - 1) : Infinity;

        sessions.forEach(session => {
            const sessionTime = new Date(session.reportDate).getTime();
            if (sessionTime < fromDate || sessionTime > toDate) return;

            session.studentRecords?.forEach(student => {
                const cccdRaw = (student['SỐ CHỨNG MINH'] || '').toString().trim();
                const sidRaw = (student['MÃ HỌC VIÊN'] || '').toString().trim();

                // Identity Key: Ưu tiên CCCD, nếu không có dùng Mã HV
                const identityKey = cccdRaw || sidRaw;
                if (!identityKey) return;

                // Filter by Class & Status
                if (selectedClass !== 'all' && student['HẠNG GPLX'] !== selectedClass) return;

                const isAbsent = isStudentAbsent(student);
                const isPass = isStudentPassed(student);
                if (selectedStatus === 'passed' && !isPass) return;
                if (selectedStatus === 'absent' && !isAbsent) return;
                if (selectedStatus === 'failed' && (isPass || isAbsent)) return;

                // Filter by Search Term
                if (term) {
                    const name = (student['HỌ VÀ TÊN'] || '').toLowerCase();
                    const cccd = cccdRaw.toLowerCase();
                    const sid = sidRaw.toLowerCase();
                    const sbd = (student['SỐ BÁO DANH'] || '').toString().toLowerCase();
                    if (!name.includes(term) && !sid.includes(term) && !cccd.includes(term) && sbd !== term) return;
                }

                if (!studentMap.has(identityKey)) {
                    studentMap.set(identityKey, {
                        studentName: student['HỌ VÀ TÊN'],
                        identityKey: identityKey,
                        cccd: cccdRaw,
                        licenseClass: student['HẠNG GPLX'],
                        associatedStudentIds: new Set<string>(),
                        attempts: []
                    });
                }

                const profile = studentMap.get(identityKey)!;
                if (sidRaw) profile.associatedStudentIds.add(sidRaw);

                profile.attempts.push({
                    sessionName: session.name,
                    reportDate: session.reportDate,
                    data: student
                });
            });
        });

        const list = Array.from(studentMap.values());
        // Sort each student's attempts by date desc
        list.forEach(s => s.attempts.sort((a, b) => new Date(b.reportDate).getTime() - new Date(a.reportDate).getTime()));
        // Sort the list by the most recent exam date of each student
        return list.sort((a, b) => new Date(b.attempts[0].reportDate).getTime() - new Date(a.attempts[0].reportDate).getTime());
    }, [sessions, searchTerm, dateFrom, dateTo, selectedClass, selectedStatus]);

    const getScoreColor = (score: string | undefined) => {
        if (!score) return 'text-gray-300';
        const s = score.trim().toUpperCase();
        if (s === 'ĐẠT') return 'text-green-600 font-bold';
        if (s === 'KHÔNG ĐẠT' || s === 'TRƯỢT') return 'text-red-600 font-bold';
        return 'text-gray-800 font-medium';
    };

    return (
        <div className="p-6 md:p-8 h-full overflow-y-auto bg-gray-50 dark:bg-gray-900 transition-colors">
            <div className="mb-6 flex justify-between items-start">
                <div>
                    <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Tra cứu Hồ sơ Thí sinh</h2>
                    <p className="text-gray-500 dark:text-gray-400 mt-1 text-sm">Tra cứu tập trung theo CCCD và quản lý lịch sử đa Mã học viên.</p>
                </div>
                <div className="text-xs bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-300 px-3 py-2 rounded-lg border border-blue-100 dark:border-blue-800 italic">
                    <i className="fa-solid fa-circle-info mr-1"></i> Hệ thống tự động gộp các thí sinh trùng số CCCD.
                </div>
            </div>

            {/* Filter Panel */}
            <div className="bg-white dark:bg-gray-800 p-5 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 mb-6 space-y-4">
                <div className="flex flex-col md:flex-row gap-4">
                    <div className="flex-1 relative">
                        <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
                        <input 
                            type="text" 
                            className="w-full pl-11 pr-4 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all dark:bg-gray-700 dark:text-white"
                            placeholder="Tên, Mã HV, SBD hoặc CCCD..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                    {(searchTerm || dateFrom || dateTo || selectedClass !== 'all' || selectedStatus !== 'all') && (
                        <button 
                            onClick={() => { setSearchTerm(''); setDateFrom(''); setDateTo(''); setSelectedClass('all'); setSelectedStatus('all'); }}
                            className="px-4 py-2 text-red-600 bg-red-50 dark:bg-red-900/20 hover:bg-red-100 rounded-lg text-sm font-medium transition-colors flex items-center justify-center gap-2"
                        >
                            <i className="fa-solid fa-filter-circle-xmark"></i> Xóa lọc
                        </button>
                    )}
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                    <div className="flex items-center gap-2 bg-gray-50 dark:bg-gray-700 p-1 rounded-lg border dark:border-gray-600">
                        <input type="date" className="w-full bg-transparent border-none text-xs p-2 text-gray-600 dark:text-gray-300" value={dateFrom} onChange={(e) => setDateFrom(e.target.value)} title="Từ ngày" />
                        <span className="text-gray-400"><i className="fa-solid fa-arrow-right"></i></span>
                        <input type="date" className="w-full bg-transparent border-none text-xs p-2 text-gray-600 dark:text-gray-300" value={dateTo} onChange={(e) => setDateTo(e.target.value)} title="Đến ngày" />
                    </div>
                    <select className="px-3 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg text-sm dark:bg-gray-700 dark:text-white outline-none" value={selectedClass} onChange={(e) => setSelectedClass(e.target.value)}>
                        <option value="all">Tất cả Hạng</option>
                        {uniqueClasses.map(cls => <option key={cls} value={cls}>Hạng {cls}</option>)}
                    </select>
                    <select className="px-3 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg text-sm dark:bg-gray-700 dark:text-white outline-none" value={selectedStatus} onChange={(e) => setSelectedStatus(e.target.value as any)}>
                        <option value="all">Tất cả Trạng thái</option>
                        <option value="passed">Đạt</option>
                        <option value="failed">Trượt</option>
                        <option value="absent">Vắng thi</option>
                    </select>
                </div>
            </div>

            {isLoading ? (
                <div className="text-center py-20"><i className="fa-solid fa-spinner animate-spin text-3xl text-blue-500"></i></div>
            ) : (
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                    {searchResults.map((student, index) => {
                        const latest = student.attempts[0].data;
                        const hasMultipleIds = student.associatedStudentIds.size > 1;

                        return (
                            <div key={index} className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 p-5 hover:border-blue-300 dark:hover:border-blue-500 transition-all group">
                                <div className="flex justify-between items-start mb-4">
                                    <div className="flex-1">
                                        <h3 className="text-lg font-bold text-gray-800 dark:text-white group-hover:text-blue-600 transition-colors">{student.studentName}</h3>
                                        <div className="flex flex-wrap items-center gap-2 mt-2">
                                            {student.cccd && (
                                                <span className="flex items-center gap-1.5 font-mono bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 px-2 py-0.5 rounded text-xs border border-blue-100 dark:border-blue-800" title="Định danh chính">
                                                    <i className="fa-solid fa-id-card"></i> {student.cccd}
                                                </span>
                                            )}

                                            {/* Danh sách Mã HV liên quan */}
                                            {hasMultipleIds ? (
                                                <div className="flex items-center gap-1.5 px-2 py-0.5 bg-orange-50 dark:bg-orange-900/30 text-orange-700 dark:text-orange-300 rounded text-xs border border-orange-100 dark:border-orange-800 cursor-help" title="Cảnh báo: Phát hiện nhiều Mã học viên trùng CCCD">
                                                    <i className="fa-solid fa-triangle-exclamation"></i>
                                                    <span className="font-bold">Đa Mã:</span>
                                                    {Array.from(student.associatedStudentIds).join(', ')}
                                                </div>
                                            ) : (
                                                <span className="font-mono bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-400 px-2 py-0.5 rounded text-xs">
                                                    Mã: {Array.from(student.associatedStudentIds)[0] || '---'}
                                                </span>
                                            )}
                                        </div>
                                    </div>
                                    <div className="text-right ml-4">
                                        <div className="px-3 py-1 bg-blue-600 text-white rounded-full text-xs font-bold shadow-sm">
                                            {student.attempts.length} Lượt thi
                                        </div>
                                        <div className="text-[10px] text-gray-400 mt-2 uppercase font-bold tracking-wider">Hạng: {student.licenseClass}</div>
                                    </div>
                                </div>

                                <div className="bg-gray-50 dark:bg-gray-750 rounded-lg p-3 mb-4 grid grid-cols-4 gap-2 text-center text-xs">
                                    <div className="border-r dark:border-gray-700"><div className="text-gray-400 font-bold mb-1 uppercase text-[10px]">Lý thuyết</div><div className={getScoreColor(latest['LÝ THUYẾT'])}>{latest['LÝ THUYẾT'] || '-'}</div></div>
                                    <div className="border-r dark:border-gray-700"><div className="text-gray-400 font-bold mb-1 uppercase text-[10px]">Mô phỏng</div><div className={getScoreColor(latest['MÔ PHỎNG'])}>{latest['MÔ PHỎNG'] || '-'}</div></div>
                                    <div className="border-r dark:border-gray-700"><div className="text-gray-400 font-bold mb-1 uppercase text-[10px]">Sa hình</div><div className={getScoreColor(latest['SA HÌNH'])}>{latest['SA HÌNH'] || '-'}</div></div>
                                    <div><div className="text-gray-400 font-bold mb-1 uppercase text-[10px]">Đ.Trường</div><div className={getScoreColor(latest['ĐƯỜNG TRƯỜNG'])}>{latest['ĐƯỜNG TRƯỜNG'] || '-'}</div></div>
                                </div>

                                <button 
                                    onClick={() => setSelectedStudentHistory(student)}
                                    className="w-full py-2.5 bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 hover:bg-blue-600 hover:text-white dark:hover:bg-blue-600 dark:hover:text-white rounded-lg text-sm font-bold transition-all flex items-center justify-center gap-2 border border-blue-100 dark:border-blue-800"
                                >
                                    <i className="fa-solid fa-clock-rotate-left"></i> Xem lịch sử thi chi tiết
                                </button>
                            </div>
                        );
                    })}
                </div>
            )}

            {/* History Modal */}
            {selectedStudentHistory && (
                <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
                    <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl w-full max-w-4xl max-h-[90vh] flex flex-col overflow-hidden animate-slide-up">
                        <header className="p-6 border-b dark:border-gray-700 flex justify-between items-center bg-gray-50 dark:bg-gray-750">
                            <div>
                                <h2 className="text-xl font-bold text-gray-900 dark:text-white">Lịch sử thi: {selectedStudentHistory.studentName}</h2>
                                <div className="flex items-center gap-3 mt-1">
                                    <span className="text-sm text-gray-500 font-medium">CCCD: {selectedStudentHistory.cccd || 'N/A'}</span>
                                    <span className="w-1 h-1 bg-gray-300 rounded-full"></span>
                                    <span className="text-sm text-gray-500 font-medium">Hạng: {selectedStudentHistory.licenseClass}</span>
                                </div>
                            </div>
                            <button onClick={() => setSelectedStudentHistory(null)} className="w-10 h-10 flex items-center justify-center text-gray-400 hover:text-gray-900 dark:hover:text-white rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-all">
                                <i className="fa-solid fa-xmark text-xl"></i>
                            </button>
                        </header>

                        <div className="flex-1 overflow-y-auto p-6 bg-white dark:bg-gray-800">
                            <div className="relative border-l-2 border-blue-200 dark:border-blue-900 ml-3 pl-8 space-y-8">
                                {selectedStudentHistory.attempts.map((attempt, idx) => {
                                    const isPass = isStudentPassed(attempt.data);
                                    const isAbs = isStudentAbsent(attempt.data);
                                    return (
                                        <div key={idx} className="relative">
                                            {/* Time dot */}
                                            <div className={`absolute -left-11 top-1 w-6 h-6 rounded-full border-4 border-white dark:border-gray-800 flex items-center justify-center shadow-sm ${
                                                isAbs ? 'bg-gray-400' : isPass ? 'bg-green-500' : 'bg-red-500'
                                            }`}>
                                                {isPass ? <i className="fa-solid fa-check text-[10px] text-white"></i> : <i className="fa-solid fa-xmark text-[10px] text-white"></i>}
                                            </div>

                                            <div className="bg-gray-50 dark:bg-gray-750 p-5 rounded-xl border border-gray-100 dark:border-gray-700 shadow-sm hover:shadow-md transition-shadow">
                                                <div className="flex flex-col md:flex-row justify-between md:items-start mb-4 gap-3">
                                                    <div>
                                                        <h4 className="font-bold text-gray-800 dark:text-white text-base">{attempt.sessionName}</h4>
                                                        <div className="flex items-center gap-3 mt-1 text-xs text-gray-500 font-medium">
                                                            <span><i className="fa-regular fa-calendar-check mr-1 text-blue-500"></i> {new Date(attempt.reportDate).toLocaleDateString('vi-VN')}</span>
                                                            <span className="w-1 h-1 bg-gray-300 rounded-full"></span>
                                                            <span>Mã HV: <span className="text-blue-600 dark:text-blue-400 font-bold">{attempt.data['MÃ HỌC VIÊN']}</span></span>
                                                        </div>
                                                    </div>
                                                    <div className={`self-start px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border ${
                                                        isAbs ? 'bg-gray-200 text-gray-600 border-gray-300' : isPass ? 'bg-green-100 text-green-700 border-green-200' : 'bg-red-100 text-red-700 border-red-200'
                                                    }`}>
                                                        {isAbs ? 'VẮNG' : isPass ? 'ĐẠT SÁT HẠCH' : 'KHÔNG ĐẠT'}
                                                    </div>
                                                </div>

                                                <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                                                    <div className="bg-white dark:bg-gray-800 p-3 rounded-lg border border-gray-100 dark:border-gray-600 text-center">
                                                        <div className="text-[10px] text-gray-400 font-bold uppercase mb-1">Lý thuyết</div>
                                                        <div className={`text-sm ${getScoreColor(attempt.data['LÝ THUYẾT'])}`}>{attempt.data['LÝ THUYẾT'] || 'N/A'}</div>
                                                    </div>
                                                    <div className="bg-white dark:bg-gray-800 p-3 rounded-lg border border-gray-100 dark:border-gray-600 text-center">
                                                        <div className="text-[10px] text-gray-400 font-bold uppercase mb-1">Mô phỏng</div>
                                                        <div className={`text-sm ${getScoreColor(attempt.data['MÔ PHỎNG'])}`}>{attempt.data['MÔ PHỎNG'] || 'N/A'}</div>
                                                    </div>
                                                    <div className="bg-white dark:bg-gray-800 p-3 rounded-lg border border-gray-100 dark:border-gray-600 text-center">
                                                        <div className="text-[10px] text-gray-400 font-bold uppercase mb-1">Sa hình</div>
                                                        <div className={`text-sm ${getScoreColor(attempt.data['SA HÌNH'])}`}>{attempt.data['SA HÌNH'] || 'N/A'}</div>
                                                    </div>
                                                    <div className="bg-white dark:bg-gray-800 p-3 rounded-lg border border-gray-100 dark:border-gray-600 text-center">
                                                        <div className="text-[10px] text-gray-400 font-bold uppercase mb-1">Đường trường</div>
                                                        <div className={`text-sm ${getScoreColor(attempt.data['ĐƯỜNG TRƯỜNG'])}`}>{attempt.data['ĐƯỜNG TRƯỜNG'] || 'N/A'}</div>
                                                    </div>
                                                </div>
                                                <div className="mt-4 pt-3 border-t dark:border-gray-700 text-[11px] text-gray-500 flex flex-wrap gap-x-4 gap-y-1">
                                                    <div><span className="font-bold">Nội dung đăng ký:</span> <span className="text-blue-600 dark:text-blue-400 font-mono font-bold">{attempt.data['NỘI DUNG THI'] || '---'}</span></div>
                                                    <div><span className="font-bold">SBD:</span> <span className="text-gray-700 dark:text-gray-300 font-bold">{attempt.data['SỐ BÁO DANH']}</span></div>
                                                    <div><span className="font-bold">Cư trú:</span> <span className="text-gray-700 dark:text-gray-300">{attempt.data['NƠI CƯ TRÚ'] || '---'}</span></div>
                                                </div>
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>

                        <footer className="p-4 bg-gray-50 dark:bg-gray-750 border-t dark:border-gray-700 text-center">
                            <button onClick={() => setSelectedStudentHistory(null)} className="px-12 py-2.5 bg-gray-800 dark:bg-gray-700 text-white rounded-xl font-bold hover:bg-gray-900 transition-all shadow-md">Đóng lịch sử</button>
                        </footer>
                    </div>
