    const [conflicts, setConflicts] = useState<ConflictWarning[]>([]);
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);
    const [darkMode, setDarkMode] = useState<boolean>(() => localStorage.getItem('theme') === 'dark');

    useEffect(() => {
        if (darkMode) {
            document.documentElement.classList.add('dark');
            localStorage.setItem('theme', 'dark');
        } else {
            document.documentElement.classList.remove('dark');
            localStorage.setItem('theme', 'light');
        }
    }, [darkMode]);

    const [reportMetadata, setReportMetadata] = useState<ReportMetadata>({
        meetingTime: '18 giờ 00 phút',
        meetingLocation: 'Trung tâm dạy nghề và Sát hạch lái xe Đông Đô',
        organizer: 'Giám đốc Công an tỉnh',
        attendees: [
            { id: '1', name: 'Đồng chí: Trung tá Dương Kim Giang', role: 'Phó Trưởng phòng, Chủ tịch Hội đồng' },
            { id: '2', name: 'Đồng chí: Trung tá Trần Duy Giang', role: 'Đội trưởng, Phó Chủ tịch Hội đồng' },
            { id: '3', name: 'Ông: Vũ Tiến Tuế', role: 'Giám đốc Trung tâm sát hạch, Ủy viên' },
            { id: '4', name: 'Đồng chí: Vương Mai Phương', role: 'Thư ký' },
        ],
        technicalErrorSBD: '',
    });

    const loadData = async () => {
        const [sessions, units] = await Promise.all([
            storageService.getAllSessions(),
            storageService.getAllTrainingUnits()
        ]);
        setSavedSessions(sessions);
        setTrainingUnits(units);
    };

    const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => setToast({ message, type });

    useEffect(() => {
        loadData();
    }, []);

    const handleExcelSubmit = (rawRecords: StudentRecord[]) => {
        setIsLoading(true);
        setError(null);
        setConflicts([]);
        try {
            const cleanRecords = normalizeData(rawRecords);
            const processedData = processExcelData(cleanRecords);
            const detectedConflicts = checkHistoricalConflicts(cleanRecords, savedSessions);
            setConflicts(detectedConflicts);
            setStudentRecords(cleanRecords);
            setAppData(processedData);
            if (detectedConflicts.length > 0) {
                showToast(`Phát hiện ${detectedConflicts.length} thí sinh nghi vấn nội dung thi!`, 'info');
            } else {
                showToast('Xử lý dữ liệu thành công!', 'info');
            }
        } catch (e) {
             setError(`Lỗi xử lý file Excel: ${(e as Error).message}`);
             showToast('Lỗi xử lý file Excel', 'error');
        } finally {
            setIsLoading(false);
        }
    };

    const grandTotal = useMemo<LicenseClassData | null>(() => {
        if (!appData) return null;
        const allRows = [...appData.firstTime.rows, ...appData.retake.rows];
        if (allRows.length === 0) return null;
        return allRows.reduce((acc, row) => {
            acc.totalApplications += row.totalApplications;
            acc.totalParticipants += row.totalParticipants;
            acc.theory.total += row.theory.total; acc.theory.pass += row.theory.pass; acc.theory.fail += row.theory.fail;
            acc.simulation.total += row.simulation.total; acc.simulation.pass += row.simulation.pass; acc.simulation.fail += row.simulation.fail;
            acc.practicalCourse.total += row.practicalCourse.total; acc.practicalCourse.pass += row.practicalCourse.pass; acc.practicalCourse.fail += row.practicalCourse.fail;
            acc.onRoad.total += row.onRoad.total; acc.onRoad.pass += row.onRoad.pass; acc.onRoad.fail += row.onRoad.fail;
            acc.finalPass += row.finalPass;
            return acc;
        }, {
            class: 'a+b', totalApplications: 0, totalParticipants: 0,
            theory: { total: 0, pass: 0, fail: 0 }, simulation: { total: 0, pass: 0, fail: 0 },
            practicalCourse: { total: 0, pass: 0, fail: 0 }, onRoad: { total: 0, pass: 0, fail: 0 },
            finalPass: 0,
        });
    }, [appData]);

    const handleSaveSession = async (name: string, reportDate: Date) => {
        if (!appData || !grandTotal || !studentRecords) {
            showToast('Không có dữ liệu để lưu!', 'error');
            return;
        }
        setIsLoading(true);
        try {
            const newSession: SavedSession = {
                id: Date.now().toString(), 
                name: name.trim() || `Kỳ sát hạch ${reportDate.toLocaleDateString('vi-VN')}`, 
                createdAt: Date.now(),
                reportDate: reportDate.toISOString(), 
                studentRecords, 
                appData,
                grandTotal, 
                reportMetadata, 
                trainingUnits
            };
            await storageService.saveSession(newSession);
            await loadData();
            setAppData(null); 
            setStudentRecords(null); 
            setConflicts([]);
            setCurrentView('dashboard');
            showToast('Đã lưu kỳ sát hạch thành công!', 'success');
        } catch (err) {
            console.error("Save Error:", err);
            showToast(`Lỗi khi lưu dữ liệu: ${(err as Error).message}`, 'error');
        } finally {
            setIsLoading(false);
        }
    };

    const handleSelectSession = async (session: SavedSession) => {
        setIsLoading(true);
        try {
            let fullSession = await storageService.getSessionById(session.id);
            if (!fullSession) fullSession = session;
            setSelectedSession(fullSession);
            setAppData(fullSession.appData);
            setStudentRecords(fullSession.studentRecords);
            setReportMetadata(fullSession.reportMetadata);
            setTrainingUnits(fullSession.trainingUnits || []);
            setConflicts([]);
            setCurrentView('detail');
        } catch (err) {
            showToast('Lỗi tải thông tin kỳ sát hạch', 'error');
        } finally {
            setIsLoading(false);
        }
    };

    const handleStudentUpdate = (id: string, field: string, value: any) => {
        if (!studentRecords) return;
        const newRecords = studentRecords.map(r => {
            if (String(r['SỐ BÁO DANH']) === id) {
                return { ...r, [field]: value };
            }
            return r;
        });
        const reprocessedData = processExcelData(newRecords);
        setStudentRecords(newRecords);
        setAppData(reprocessedData);
        showToast('Đã cập nhật dữ liệu thí sinh', 'info');
    };

    return (
        <div className={`flex h-screen bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-200 font-sans overflow-hidden transition-colors duration-200 ${darkMode ? 'dark' : ''}`}>
            <AdminSidebar 
                currentView={currentView === 'detail' ? 'dashboard' : currentView} 
                onChangeView={(v) => {
                    if (v === 'create') { setAppData(null); setStudentRecords(null); setConflicts([]); }
                    setCurrentView(v);
                }} 
                darkMode={darkMode} 
                onToggleDarkMode={() => setDarkMode(!darkMode)} 
            />
            <main className="flex-1 h-full relative flex flex-col min-w-0">
                {currentView === 'dashboard' && <SessionList sessions={savedSessions} onSelectSession={handleSelectSession} onDeleteSession={async id => { await storageService.deleteSession(id); loadData(); }} onCreateNew={() => setCurrentView('create')} onRefresh={loadData} />}
                {currentView === 'create' && (
                    appData ? <ReportDashboardPage summaryData={appData} studentRecords={studentRecords} grandTotal={grandTotal} reportMetadata={reportMetadata} mode="preview" onSaveSession={handleSaveSession} trainingUnits={trainingUnits} onStudentUpdate={handleStudentUpdate} isLoading={isLoading} conflicts={conflicts} />
                    : <DataInputPage onExcelSubmit={handleExcelSubmit} isLoading={isLoading} error={error} onClearData={() => { setAppData(null); setConflicts([]); }} reportMetadata={reportMetadata} onMetadataChange={setReportMetadata} conflicts={conflicts} />
                )}
                {currentView === 'detail' && selectedSession && appData && <ReportDashboardPage summaryData={appData} studentRecords={studentRecords} grandTotal={grandTotal} reportMetadata={reportMetadata} mode="view" initialReportDate={selectedSession.reportDate} sessionName={selectedSession.name} trainingUnits={trainingUnits} onStudentUpdate={handleStudentUpdate} isLoading={isLoading} onUpdateSession={async (name, date, meta) => {
                    const updated = { ...selectedSession, name, reportDate: date.toISOString(), reportMetadata: meta };
                    setIsLoading(true);
                    try {
                        await storageService.saveSession(updated);
                        await loadData();
                        showToast('Cập nhật kỳ sát hạch thành công', 'success');
                    } catch (err) {
                        showToast(`Lỗi: ${(err as Error).message}`, 'error');
                    } finally {
                        setIsLoading(false);
                    }
                }} />}
                {currentView === 'aggregate-report' && <AggregateReportPage />}
                {currentView === 'student-lookup' && <StudentLookupPage />}
                {currentView === 'conflict-audit' && <ConflictAuditPage sessions={savedSessions} />}
                {currentView === 'training-units' && <TrainingUnitManager trainingUnits={trainingUnits} onUnitsImport={units => { setTrainingUnits(units); loadData(); }} />}
                {currentView === 'settings' && <SettingsPage onRefresh={() => loadData()} />}
            </main>
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        </div>
    );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import type { AppData, LicenseClassData, StudentRecord, ReportMetadata, TrainingUnit, ConflictWarning } from '../../types';
import { GeneralReport } from './GeneralReport';
import { StudentListReport } from './StudentListReport';
import { UnitStatisticsReport } from './UnitStatisticsReport';
import { MasterStudentListReport } from './MasterStudentListReport';
import { isStudentPassed, isStudentAbsent } from '../../services/reportUtils';
import { exportGeneralReportToExcel, exportStudentListToExcel, exportUnitStatisticsToExcel, exportMasterListToExcel } from '../../services/excelGenerator';
import { ReportMetadataModal } from '../ReportMetadataModal';

interface ReportDashboardPageProps {
    summaryData: AppData;
    studentRecords: StudentRecord[] | null;
    grandTotal: LicenseClassData | null;
    reportMetadata: ReportMetadata;

    // Props mới cho tính năng lưu trữ
    mode?: 'preview' | 'view'; // 'preview' khi tạo mới, 'view' khi xem từ DB
    onSaveSession?: (sessionName: string, reportDate: Date) => void;
    // New prop for updating existing session
    onUpdateSession?: (sessionName: string, reportDate: Date, metadata: ReportMetadata) => void;
    initialReportDate?: string; // ISO String
    sessionName?: string; // Initial name for view mode

    // Props for training units
    trainingUnits?: TrainingUnit[];

    // Inline Edit Prop
    onStudentUpdate?: (id: string, field: string, value: any) => void;

    // Thêm prop isLoading để hiển thị trạng thái nút
    isLoading?: boolean;

    // Prop cho đối soát nội dung thi
    conflicts?: ConflictWarning[];
}

type ReportView = 'summary' | 'unit-stats' | 'passed' | 'failed' | 'absent' | 'master-list' | 'audit';

export const ReportDashboardPage: React.FC<ReportDashboardPageProps> = ({ 
    summaryData, 
    studentRecords, 
    grandTotal, 
    reportMetadata,
    mode = 'preview',
    onSaveSession,
    onUpdateSession,
    initialReportDate,
    sessionName: initialSessionName,
    trainingUnits = [],
    onStudentUpdate,
    isLoading = false,
    conflicts = []
}) => {
    const [view, setView] = useState<ReportView>('summary');
    const [reportDate, setReportDate] = useState<Date>(initialReportDate ? new Date(initialReportDate) : new Date());
    const [sessionName, setSessionName] = useState(initialSessionName || `Kỳ sát hạch ngày ${new Date().toLocaleDateString('vi-VN')}`);

    // Editing states
    const [isEditing, setIsEditing] = useState(false);
    const [localMetadata, setLocalMetadata] = useState<ReportMetadata>(reportMetadata);
    const [isMetadataModalOpen, setIsMetadataModalOpen] = useState(false);

    // Sync props to state when switching sessions in view mode
    useEffect(() => {
        if (mode === 'view') {
            if (initialReportDate) setReportDate(new Date(initialReportDate));
            if (initialSessionName) setSessionName(initialSessionName);
            setLocalMetadata(reportMetadata);
            setIsEditing(false); // Reset edit mode when switching sessions
        }
    }, [initialReportDate, initialSessionName, reportMetadata, mode]);

    // Cập nhật tên mặc định khi ngày thay đổi trong mode preview
    useEffect(() => {
        if (mode === 'preview' && !initialReportDate) {
             setSessionName(`Kỳ sát hạch ngày ${reportDate.toLocaleDateString('vi-VN')}`);
        }
    }, [reportDate, mode, initialReportDate]);

    const hasDetailedData = studentRecords && studentRecords.length > 0;

    // Reset view to summary if detailed data becomes unavailable
    useEffect(() => {
        if (!hasDetailedData) {
            setView('summary');
        }
    }, [hasDetailedData]);

    const { passedStudents, failedStudents, absentStudents } = useMemo(() => {
        if (!hasDetailedData) {
            return { passedStudents: [], failedStudents: [], absentStudents: [] };
        }
        const passed: StudentRecord[] = [];
        const failed: StudentRecord[] = [];
        const absent: StudentRecord[] = [];

        for (const record of studentRecords!) {
            if (isStudentAbsent(record)) {
                absent.push(record);
            } else if (isStudentPassed(record)) {
                passed.push(record);
            } else {
                failed.push(record);
            }
        }
        return { passedStudents: passed, failedStudents: failed, absentStudents: absent };
    }, [studentRecords, hasDetailedData]);

    const handleDownload = () => {
        switch(view) {
            case 'summary':
                exportGeneralReportToExcel(summaryData, grandTotal, reportDate, localMetadata);
                break;
            case 'unit-stats':
                if (studentRecords) exportUnitStatisticsToExcel(studentRecords, trainingUnits, reportDate);
                break;
            case 'passed':
                exportStudentListToExcel(passedStudents, 'Danh_Sach_Dat', reportDate);
                break;
            case 'failed':
                exportStudentListToExcel(failedStudents, 'Danh_Sach_Truot', reportDate);
                break;
            case 'absent':
                exportStudentListToExcel(absentStudents, 'Danh_Sach_Vang', reportDate);
                break;
            case 'master-list':
                if (studentRecords) exportMasterListToExcel(studentRecords, trainingUnits, reportDate);
                break;
            case 'audit':
                alert('Tính năng xuất Excel báo cáo kiểm toán sẽ được cập nhật sau.');
                break;
        }
    };

    const handleSaveClick = () => {
        if (isLoading) return; // Chống spam click

        if (mode === 'preview' && onSaveSession) {
            onSaveSession(sessionName, reportDate);
        } else if (mode === 'view' && onUpdateSession) {
            onUpdateSession(sessionName, reportDate, localMetadata);
            setIsEditing(false);
        }
    };

    const handleCancelEdit = () => {
        setIsEditing(false);
        // Reset to initial values
        if (initialReportDate) setReportDate(new Date(initialReportDate));
        if (initialSessionName) setSessionName(initialSessionName);
        setLocalMetadata(reportMetadata);
    };

    const renderAuditView = () => {
        return (
            <div className="p-4 space-y-6 animate-fade-in">
                <div className="flex items-center gap-3 mb-4">
                    <div className="p-3 bg-orange-100 dark:bg-orange-900/30 rounded-xl text-orange-600 dark:text-orange-400">
                        <i className="fa-solid fa-shield-halved text-2xl"></i>
                    </div>
                    <div>
                        <h2 className="text-xl font-bold text-gray-800 dark:text-white uppercase tracking-tight">Báo cáo Kiểm toán & Đối soát Nội dung</h2>
                        <p className="text-sm text-gray-500">Phát hiện các sai sót đăng ký thi dựa trên lịch sử dữ liệu hệ thống.</p>
                    </div>
                </div>

                {conflicts.length === 0 ? (
                    <div className="py-20 flex flex-col items-center text-center">
                        <div className="w-20 h-20 bg-green-50 dark:bg-green-900/20 rounded-full flex items-center justify-center mb-4 text-green-500 shadow-inner">
                            <i className="fa-solid fa-check text-4xl"></i>
                        </div>
                        <h3 className="text-lg font-bold text-gray-800 dark:text-white">Dữ liệu hoàn toàn Nhất quán</h3>
                        <p className="text-gray-500 max-w-sm mt-1">Không phát hiện thí sinh nào đang dự thi lại những nội dung đã đạt trong quá khứ.</p>
                    </div>
                ) : (
                    <div className="space-y-4">
                        <div className="p-4 bg-orange-50 dark:bg-orange-900/20 border-l-4 border-orange-500 rounded-r-lg">
                            <p className="text-sm text-orange-800 dark:text-orange-300 font-medium">
                                <i className="fa-solid fa-circle-exclamation mr-2"></i>
                                Phát hiện <strong>{conflicts.length}</strong> thí sinh nghi vấn. Các thí sinh này được ghi nhận đã "ĐẠT" phần thi tương ứng tại các kỳ sát hạch trước đó.
                            </p>
                        </div>

                        <div className="overflow-hidden border border-gray-200 dark:border-gray-700 rounded-xl shadow-sm">
                            <table className="w-full text-left text-sm">
                                <thead className="bg-gray-100 dark:bg-gray-800 text-gray-700 dark:text-gray-300 font-bold uppercase text-[11px] tracking-wider">
                                    <tr>
                                        <th className="px-6 py-4">Thí sinh</th>
                                        <th className="px-6 py-4 text-center">Nội dung trùng</th>
                                        <th className="px-6 py-4">Kết quả lịch sử</th>
                                        <th className="px-6 py-4 text-center">Ngày đạt</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                                    {conflicts.map((c, idx) => (
                                        <tr key={idx} className="bg-white dark:bg-gray-800 hover:bg-orange-50 dark:hover:bg-orange-900/10 transition-colors">
                                            <td className="px-6 py-4">
                                                <div className="font-bold text-gray-900 dark:text-white">{c.studentName}</div>
                                                <div className="text-xs text-gray-400 font-mono">ID: {c.studentId}</div>
                                            </td>
                                            <td className="px-6 py-4 text-center">
                                                <span className="px-3 py-1 bg-orange-100 dark:bg-orange-900/40 text-orange-700 dark:text-orange-300 rounded-full text-[11px] font-black uppercase">
                                                    {c.conflictPart}
                                                </span>
                                            </td>
                                            <td className="px-6 py-4">
                                                <div className="text-gray-700 dark:text-gray-300 font-medium">{c.previousSessionName}</div>
                                            </td>
                                            <td className="px-6 py-4 text-center text-gray-500 italic">
                                                {c.previousDate}
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}
            </div>
        );
    };

    const renderActiveReport = () => {
        switch(view) {
            case 'summary':
                return <GeneralReport appData={summaryData} grandTotal={grandTotal} reportDate={reportDate} reportMetadata={localMetadata} />;
            case 'unit-stats':
                return studentRecords ? <UnitStatisticsReport students={studentRecords} trainingUnits={trainingUnits} reportDate={reportDate} /> : null;
            case 'passed':
                return <StudentListReport 
                            title="DANH SÁCH THÍ SINH ĐẠT SÁT HẠCH LÁI XE Ô TÔ" 
                            students={passedStudents} 
                            reportType="passed" 
                            reportDate={reportDate} 
                            trainingUnits={trainingUnits}
                            onStudentUpdate={onStudentUpdate}
                        />;
            case 'failed':
                return <StudentListReport 
                            title="DANH SÁCH THÍ SINH TRƯỢT SÁT HẠCH LÁI XE Ô TÔ" 
                            students={failedStudents} 
                            reportType="failed" 
                            reportDate={reportDate} 
                            trainingUnits={trainingUnits}
                            onStudentUpdate={onStudentUpdate}
                        />;
            case 'absent':
                 return <StudentListReport 
                            title="DANH SÁCH THÍ SINH VẮNG SÁT HẠCH LÁI XE Ô TÔ" 
                            students={absentStudents} 
                            reportType="absent" 
                            reportDate={reportDate} 
                            trainingUnits={trainingUnits}
                            onStudentUpdate={onStudentUpdate}
                        />;
            case 'master-list':
                return studentRecords ? <MasterStudentListReport students={studentRecords} trainingUnits={trainingUnits} reportDate={reportDate} /> : null;
            case 'audit':
                return renderAuditView();
            default:
                return null;
        }
    };

    const TabButton: React.FC<{reportView: ReportView; label: string; icon: string; badge?: number; colorClass?: string}> = ({reportView, label, icon, badge, colorClass}) => (
        <button
            onClick={() => setView(reportView)}
            className={`px-3 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 whitespace-nowrap relative ${
                view === reportView 
                    ? (colorClass || 'bg-blue-600 text-white shadow') 
                    : 'text-gray-600 dark:text-gray-300 hover:text-blue-600 dark:hover:text-blue-400 hover:bg-gray-100 dark:hover:bg-gray-700'
            }`}
        >
            <i className={`fa-solid ${icon}`}></i> {label}
            {badge !== undefined && badge > 0 && (
                <span className="absolute -top-1 -right-1 flex h-4 w-4 items-center justify-center rounded-full bg-red-500 text-[10px] font-bold text-white animate-bounce">
                    {badge}
                </span>
            )}
        </button>
    );

    return (
        <div className="flex flex-col h-full bg-gray-50 dark:bg-gray-900">
            {/* Control Bar */}
            <div className="bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 p-3 print:hidden flex flex-col xl:flex-row gap-4 justify-between xl:items-start sticky top-0 z-10 shadow-sm">

                {/* Left: View Switcher */}
                <div className="flex flex-col gap-2 w-full xl:w-auto overflow-x-auto pb-2 xl:pb-0">
                    {/* Group 1: General Reports */}
                    <div className="flex items-center gap-1 bg-gray-50 dark:bg-gray-700 p-1 rounded-lg border border-gray-100 dark:border-gray-600 w-fit">
                        <span className="text-[10px] uppercase font-bold text-gray-400 px-2">Tổng hợp</span>
                        <TabButton reportView="summary" label="Biên bản chung" icon="fa-chart-pie" />
                        {hasDetailedData && <TabButton reportView="unit-stats" label="Thống kê Đơn vị" icon="fa-building-columns" />}
                        {(mode === 'preview' || conflicts.length > 0) && (
                            <TabButton 
                                reportView="audit" 
                                label="Kiểm toán nội dung" 
                                icon="fa-shield-halved" 
                                badge={conflicts.length}
                                colorClass={conflicts.length > 0 ? "bg-orange-600 text-white shadow" : undefined}
                            />
                        )}
                    </div>

                    {/* Group 2: Detailed Lists */}
                    {hasDetailedData && (
                        <div className="flex items-center gap-1 bg-gray-50 dark:bg-gray-700 p-1 rounded-lg border border-gray-100 dark:border-gray-600 w-fit">
                            <span className="text-[10px] uppercase font-bold text-gray-400 px-2">Danh sách</span>
                            <TabButton reportView="master-list" label="Tất cả (Chi tiết)" icon="fa-list" />
                            <div className="w-px h-4 bg-gray-300 dark:bg-gray-600 mx-1"></div>
                            <TabButton reportView="passed" label="Đạt" icon="fa-circle-check" />
                            <TabButton reportView="failed" label="Trượt" icon="fa-circle-xmark" />
                            <TabButton reportView="absent" label="Vắng" icon="fa-user-slash" />
                        </div>
                    )}
                </div>

                {/* Right: Actions */}
                <div className="flex flex-col sm:flex-row items-end sm:items-center gap-3">

                    {/* Mode specific controls */}
                    {(mode === 'preview' || isEditing) ? (
                        <div className="flex items-center gap-2 bg-blue-50 dark:bg-blue-900/30 p-2 rounded-lg border border-blue-100 dark:border-blue-800 animate-fade-in">
                             <div className="flex flex-col">
                                <label className="text-[10px] text-blue-600 dark:text-blue-400 font-bold uppercase mb-0.5">Tên kỳ sát hạch</label>
                                <input 
                                    type="text"
                                    value={sessionName}
                                    onChange={(e) => setSessionName(e.target.value)}
                                    className="px-2 py-1.5 border border-blue-200 dark:border-blue-700 rounded-md text-sm w-48 sm:w-64 focus:ring-2 focus:ring-blue-500 outline-none dark:bg-gray-800 dark:text-white"
                                    placeholder="Nhập tên kỳ..."
                                    disabled={isLoading}
                                />
                             </div>

                             <div className="flex flex-col">
                                <label className="text-[10px] text-blue-600 dark:text-blue-400 font-bold uppercase mb-0.5">Ngày báo cáo</label>
                                <input 
                                    type="date" 
                                    value={reportDate.toISOString().split('T')[0]}
                                    onChange={(e) => setReportDate(new Date(e.target.value))}
                                    className="px-2 py-1.5 border border-blue-200 dark:border-blue-700 rounded-md text-sm w-36 focus:ring-2 focus:ring-blue-500 outline-none dark:bg-gray-800 dark:text-white"
                                    disabled={isLoading}
