            {/* Report Content */}
            <div className="report-content flex-1 p-8 bg-gray-50 dark:bg-gray-900 overflow-y-auto print:p-0 print:bg-white">
                 <div className="max-w-[297mm] mx-auto bg-white shadow-lg p-10 min-h-[210mm] print:shadow-none print:p-0 transition-colors">
                    {renderActiveReport()}
                 </div>
            </div>

            {/* Metadata Modal */}
            {isMetadataModalOpen && (
                <ReportMetadataModal
                    initialMetadata={localMetadata}
                    onSave={(newMetadata) => {
                        setLocalMetadata(newMetadata);
                        setIsMetadataModalOpen(false);
                    }}
                    onClose={() => setIsMetadataModalOpen(false)}
                />
            )}
        </div>
    );
};

import React, { useMemo, useState } from 'react';
import type { SavedSession, ConflictWarning, StudentRecord } from '../../types';
import { getResultStatus, checkHistoricalConflicts } from '../../services/reportUtils';
import { normalizeData } from '../../services/excelProcessor';

declare const XLSX: any;

interface ConflictDetail {
    part: string;
    previousSessionName: string;
    previousDate: string;
    currentSessionName?: string;
    currentDate?: string;
}

interface GroupedFinding {
    studentName: string;
    studentId: string;
    conflicts: ConflictDetail[];
}

export const ConflictAuditPage: React.FC<{ sessions: SavedSession[] }> = ({ sessions }) => {
    const [activeTab, setActiveTab] = useState<'upload' | 'history'>('upload');
    const [searchTerm, setSearchTerm] = useState('');
    const [isProcessing, setIsProcessing] = useState(false);
    const [uploadedConflicts, setUploadedConflicts] = useState<ConflictWarning[]>([]);
    const [hasChecked, setHasChecked] = useState(false);

    // Hàm gom nhóm các cảnh báo theo Mã học viên
    const groupConflicts = (warnings: ConflictWarning[]): GroupedFinding[] => {
        const map = new Map<string, GroupedFinding>();

        warnings.forEach(w => {
            if (!map.has(w.studentId)) {
                map.set(w.studentId, {
                    studentId: w.studentId,
                    studentName: w.studentName,
                    conflicts: []
                });
            }
            map.get(w.studentId)!.conflicts.push({
                part: w.conflictPart,
                previousSessionName: w.previousSessionName,
                previousDate: w.previousDate
            });
        });

        return Array.from(map.values());
    };

    // Tính toán kiểm toán toàn bộ lịch sử hệ thống (Tab History)
    const groupedHistoryFindings = useMemo(() => {
        if (sessions.length < 2) return [];

        const findingsMap = new Map<string, GroupedFinding>();
        const sortedSessions = [...sessions].sort((a, b) => 
            new Date(a.reportDate).getTime() - new Date(b.reportDate).getTime()
        );

        const passedDatabase = new Map<string, { part: string, sessionName: string, date: string }[]>();

        sortedSessions.forEach(session => {
            const sessionDateStr = new Date(session.reportDate).toLocaleDateString('vi-VN');

            session.studentRecords.forEach(record => {
                const sid = String(record['MÃ HỌC VIÊN'] || '').trim();
                if (!sid) return;

                const currentND = String(record['NỘI DUNG THI'] || '').toUpperCase().replace(/Đ/g, 'D');

                const history = passedDatabase.get(sid);
                if (history) {
                    ['L', 'M', 'H', 'D'].forEach(part => {
                        if (currentND.includes(part)) {
                            const prevPass = history.find(h => h.part === part);
                            if (prevPass) {
                                if (!findingsMap.has(sid)) {
                                    findingsMap.set(sid, {
                                        studentId: sid,
                                        studentName: record['HỌ VÀ TÊN'],
                                        conflicts: []
                                    });
                                }

                                const partName = part === 'D' ? 'Đường trường' : (part === 'L' ? 'Lý thuyết' : (part === 'M' ? 'Mô phỏng' : 'Sa hình'));

                                // Tránh trùng lặp cùng một môn trong cùng một bộ kết quả
                                if (!findingsMap.get(sid)!.conflicts.some(c => c.part === partName && c.currentSessionName === session.name)) {
                                    findingsMap.get(sid)!.conflicts.push({
                                        part: partName,
                                        previousSessionName: prevPass.sessionName,
                                        previousDate: prevPass.date,
                                        currentSessionName: session.name,
                                        currentDate: sessionDateStr
                                    });
                                }
                            }
                        }
                    });
                }

                // Cập nhật Database "Đã đạt"
                const results = [
                    { part: 'L', passed: getResultStatus(record['LÝ THUYẾT']).passed },
                    { part: 'M', passed: getResultStatus(record['MÔ PHỎNG']).passed },
                    { part: 'H', passed: getResultStatus(record['SA HÌNH']).passed },
                    { part: 'D', passed: getResultStatus(record['ĐƯỜNG TRƯỜNG']).passed },
                ];

                results.forEach(res => {
                    if (res.passed) {
                        const existing = passedDatabase.get(sid) || [];
                        if (!existing.some(e => e.part === res.part)) {
                            existing.push({ part: res.part, sessionName: session.name, date: sessionDateStr });
                            passedDatabase.set(sid, existing);
                        }
                    }
                });
            });
        });

        return Array.from(findingsMap.values()).reverse();
    }, [sessions]);

    const groupedUploadFindings = useMemo(() => groupConflicts(uploadedConflicts), [uploadedConflicts]);

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setIsProcessing(true);
            setHasChecked(false);
            const file = e.target.files[0];
            const reader = new FileReader();

            reader.onload = (event) => {
                try {
                    const data = new Uint8Array(event.target!.result as ArrayBuffer);
                    const workbook = XLSX.read(data, { type: 'array' });
                    const sheetName = workbook.SheetNames[0];
                    const worksheet = workbook.Sheets[sheetName];
                    const json: any[] = XLSX.utils.sheet_to_json(worksheet);

                    const normalized = normalizeData(json);
                    const conflicts = checkHistoricalConflicts(normalized, sessions);

                    setUploadedConflicts(conflicts);
                    setHasChecked(true);
                } catch (err) {
                    console.error("Error processing file:", err);
                    alert("Có lỗi xảy ra khi đọc file Excel.");
                } finally {
                    setIsProcessing(false);
                    e.target.value = '';
                }
            };
            reader.readAsArrayBuffer(file);
        }
    };

    const filteredHistory = groupedHistoryFindings.filter(f => 
        f.studentName.toLowerCase().includes(searchTerm.toLowerCase()) || 
        f.studentId.includes(searchTerm)
    );

    const renderConflictTable = (findings: GroupedFinding[], showCurrentSession: boolean = false) => (
        <div className="overflow-x-auto">
            <table className="w-full text-left text-sm">
                <thead className="bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-200 uppercase font-bold text-[10px] tracking-wider">
                    <tr>
                        <th className="px-6 py-4 w-1/4">Thí sinh / Mã HV</th>
                        <th className="px-6 py-4">Chi tiết nội dung nghi vấn (Đã đạt trước đó)</th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                    {findings.map((finding, idx) => (
                        <tr key={idx} className="bg-white dark:bg-gray-800 hover:bg-gray-50 dark:hover:bg-gray-900/40 transition-colors align-top">
                            <td className="px-6 py-5">
                                <div className="font-bold text-gray-900 dark:text-white text-base">{finding.studentName}</div>
                                <div className="text-xs text-blue-600 dark:text-blue-400 font-mono mt-1 flex items-center gap-1">
                                    <i className="fa-solid fa-id-card-clip"></i> ID: {finding.studentId}
                                </div>
                            </td>
                            <td className="px-6 py-5">
                                <div className="space-y-4">
                                    {finding.conflicts.map((c, cIdx) => (
                                        <div key={cIdx} className="bg-gray-50 dark:bg-gray-750 p-3 rounded-lg border border-gray-100 dark:border-gray-700 relative overflow-hidden group/item">
                                            <div className="absolute top-0 left-0 w-1 h-full bg-orange-500"></div>
                                            <div className="flex flex-wrap items-center justify-between gap-3">
                                                <div className="flex items-center gap-3">
                                                    <span className="px-2 py-1 bg-orange-100 dark:bg-orange-900/40 text-orange-700 dark:text-orange-300 rounded text-[10px] font-black uppercase border border-orange-200 dark:border-orange-800">
                                                        {c.part}
                                                    </span>
                                                    <div className="text-xs">
                                                        <div className="text-gray-400 text-[10px] font-bold uppercase mb-0.5">Đã đạt tại:</div>
                                                        <div className="font-bold text-gray-800 dark:text-gray-200">{c.previousSessionName}</div>
                                                        <div className="text-gray-500 italic text-[10px]">{c.previousDate}</div>
                                                    </div>
                                                </div>

                                                {showCurrentSession && c.currentSessionName && (
                                                    <div className="text-right border-l dark:border-gray-600 pl-4">
                                                        <div className="text-gray-400 text-[10px] font-bold uppercase mb-0.5">Kỳ thi bị trùng:</div>
                                                        <div className="font-bold text-red-600 dark:text-red-400">{c.currentSessionName}</div>
                                                        <div className="text-gray-500 italic text-[10px]">{c.currentDate}</div>
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );

    return (
        <div className="p-6 md:p-10 h-full overflow-y-auto bg-gray-50 dark:bg-gray-900 transition-colors">
            <div className="mb-6">
                <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Kiểm toán Nội dung thi</h2>
                <p className="text-gray-500 dark:text-gray-400 mt-1">Phát hiện và gom nhóm các sai sót đăng ký thi dựa trên lịch sử dữ liệu hệ thống.</p>
            </div>

            {/* Tabs Navigation */}
            <div className="flex gap-1 bg-gray-200 dark:bg-gray-800 p-1 rounded-xl w-fit mb-6">
                <button 
                    onClick={() => setActiveTab('upload')}
                    className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'upload' ? 'bg-white dark:bg-gray-700 text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}
                >
                    <i className="fa-solid fa-file-import mr-2"></i> Kiểm tra File mới
                </button>
                <button 
                    onClick={() => setActiveTab('history')}
                    className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'history' ? 'bg-white dark:bg-gray-700 text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700 dark:hover:text-gray-300'}`}
                >
                    <i className="fa-solid fa-clock-rotate-left mr-2"></i> Lịch sử Hệ thống
                </button>
            </div>

            {activeTab === 'upload' ? (
                <div className="space-y-6 animate-fade-in">
                    <div className="bg-white dark:bg-gray-800 p-8 rounded-2xl border-2 border-dashed border-gray-300 dark:border-gray-700 flex flex-col items-center justify-center text-center">
                        <div className="w-16 h-16 bg-blue-50 dark:bg-blue-900/30 rounded-full flex items-center justify-center mb-4">
                            <i className={`fa-solid ${isProcessing ? 'fa-spinner animate-spin' : 'fa-cloud-arrow-up'} text-2xl text-blue-500`}></i>
                        </div>
                        <h3 className="text-lg font-bold text-gray-800 dark:text-white">Tải lên danh sách học viên dự kiến</h3>
                        <p className="text-sm text-gray-500 dark:text-gray-400 max-w-sm mt-2">Hệ thống sẽ đối soát file với lịch sử tất cả các kỳ thi đã lưu để tìm các môn đã thi ĐẠT.</p>

                        <div className="mt-6 relative">
                            <input 
                                type="file" 
                                accept=".xlsx, .xls" 
                                onChange={handleFileUpload}
                                className="absolute inset-0 opacity-0 cursor-pointer"
                                disabled={isProcessing}
                            />
                            <button className="px-8 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg flex items-center gap-2">
                                <i className="fa-solid fa-magnifying-glass-chart"></i>
                                {isProcessing ? 'Đang phân tích...' : 'Chọn file Excel để Kiểm tra'}
                            </button>
                        </div>
                    </div>

                    {hasChecked && (
                        <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden animate-slide-up">
                            <div className="p-4 border-b dark:border-gray-700 bg-gray-50 dark:bg-gray-750 flex items-center justify-between">
                                <h4 className="font-bold text-gray-800 dark:text-white flex items-center gap-2">
                                    <i className="fa-solid fa-list-check text-blue-500"></i>
                                    Kết quả đối soát ({groupedUploadFindings.length} thí sinh nghi vấn)
                                </h4>
                            </div>

                            {groupedUploadFindings.length === 0 ? (
                                <div className="p-12 text-center">
                                    <i className="fa-solid fa-circle-check text-5xl text-green-500 mb-4"></i>
                                    <p className="text-gray-600 dark:text-gray-300 font-medium">Tuyệt vời! File sạch, không phát hiện trùng lặp nội dung đã đạt.</p>
                                </div>
                            ) : renderConflictTable(groupedUploadFindings)}
                        </div>
                    )}
                </div>
            ) : (
                <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden animate-fade-in">
                    <div className="p-4 border-b border-gray-100 dark:border-gray-700 flex items-center justify-between bg-gray-50 dark:bg-gray-750">
                        <div className="relative flex-1 max-w-md">
                            <i className="fa-solid fa-magnifying-glass absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"></i>
                            <input 
                                type="text" 
                                placeholder="Tìm học viên hoặc mã HV..." 
                                className="w-full pl-10 pr-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm dark:bg-gray-700 dark:text-white"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </div>
                        <div className="text-xs text-gray-500 font-medium">
                            Thí sinh có sai lệch lịch sử: <span className="text-orange-600 font-bold">{filteredHistory.length}</span>
                        </div>
                    </div>

                    {filteredHistory.length === 0 ? (
                        <div className="p-20 text-center">
                            <i className="fa-solid fa-shield-check text-5xl text-green-500 mb-4"></i>
                            <h3 className="text-lg font-bold text-gray-800 dark:text-white">Dữ liệu hệ thống nhất quán!</h3>
                            <p className="text-gray-500 dark:text-gray-400 mt-1">Không phát hiện sai sót chéo giữa các kỳ thi đã lưu.</p>
                        </div>
                    ) : renderConflictTable(filteredHistory, true)}
                </div>
            )}

            <style dangerouslySetInnerHTML={{ __html: `
                @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
                @keyframes slide-up { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }
                .animate-fade-in { animation: fade-in 0.3s ease-out; }
                .animate-slide-up { animation: slide-up 0.4s cubic-bezier(0.16, 1, 0.3, 1); }
            `}} />
        </div>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import type { AppData, LicenseClassData, StudentRecord, ReportMetadata, TrainingUnit, ConflictWarning } from '../../types';
import { GeneralReport } from './GeneralReport';
import { StudentListReport } from './StudentListReport';
import { UnitStatisticsReport } from './UnitStatisticsReport';
import { MasterStudentListReport } from './MasterStudentListReport';
import { isStudentPassed, isStudentAbsent } from '../../services/reportUtils';
import { exportGeneralReportToExcel, exportStudentListToExcel, exportUnitStatisticsToExcel, exportMasterListToExcel } from '../../services/excelGenerator';
import { ReportMetadataModal } from '../ReportMetadataModal';

interface ReportDashboardPageProps {
    summaryData: AppData;
    studentRecords: StudentRecord[] | null;
    grandTotal: LicenseClassData | null;
    reportMetadata: ReportMetadata;
    mode?: 'preview' | 'view';
    onSaveSession?: (sessionName: string, reportDate: Date) => void;
    onUpdateSession?: (sessionName: string, reportDate: Date, metadata: ReportMetadata) => void;
    initialReportDate?: string;
    sessionName?: string;
    trainingUnits?: TrainingUnit[];
    onStudentUpdate?: (id: string, field: string, value: any) => void;
    isLoading?: boolean;
    conflicts?: ConflictWarning[];
}

type ReportView = 'summary' | 'unit-stats' | 'passed' | 'failed' | 'absent' | 'master-list' | 'audit';

export const ReportDashboardPage: React.FC<ReportDashboardPageProps> = ({ 
    summaryData, 
    studentRecords, 
    grandTotal, 
    reportMetadata,
    mode = 'preview',
    onSaveSession,
    onUpdateSession,
    initialReportDate,
    sessionName: initialSessionName,
    trainingUnits = [],
    onStudentUpdate,
    isLoading = false,
    conflicts = []
}) => {
    const [view, setView] = useState<ReportView>('summary');
    const [reportDate, setReportDate] = useState<Date>(initialReportDate ? new Date(initialReportDate) : new Date());
    const [sessionName, setSessionName] = useState(initialSessionName || `Kỳ sát hạch ngày ${new Date().toLocaleDateString('vi-VN')}`);

    const [isEditing, setIsEditing] = useState(false);
    const [localMetadata, setLocalMetadata] = useState<ReportMetadata>(reportMetadata);
    const [isMetadataModalOpen, setIsMetadataModalOpen] = useState(false);

    useEffect(() => {
        if (mode === 'view') {
            if (initialReportDate) setReportDate(new Date(initialReportDate));
            if (initialSessionName) setSessionName(initialSessionName);
            setLocalMetadata(reportMetadata);
            setIsEditing(false);
        }
    }, [initialReportDate, initialSessionName, reportMetadata, mode]);

    useEffect(() => {
        if (mode === 'preview' && !initialReportDate) {
             setSessionName(`Kỳ sát hạch ngày ${reportDate.toLocaleDateString('vi-VN')}`);
        }
    }, [reportDate, mode, initialReportDate]);

    const hasDetailedData = studentRecords && studentRecords.length > 0;

    useEffect(() => {
        if (!hasDetailedData && view !== 'audit') {
            setView('summary');
        }
    }, [hasDetailedData, view]);

    // Gom nhóm conflicts theo Mã học viên để hiển thị gọn gàng
    const groupedConflicts = useMemo(() => {
        const map = new Map<string, { studentId: string, studentName: string, findings: any[] }>();
        conflicts.forEach(c => {
            if (!map.has(c.studentId)) {
                map.set(c.studentId, {
                    studentId: c.studentId,
                    studentName: c.studentName,
                    findings: []
                });
            }
            map.get(c.studentId)!.findings.push({
                part: c.conflictPart,
                session: c.previousSessionName,
                date: c.previousDate
            });
        });
        return Array.from(map.values());
    }, [conflicts]);

    const { passedStudents, failedStudents, absentStudents } = useMemo(() => {
        if (!hasDetailedData) {
            return { passedStudents: [], failedStudents: [], absentStudents: [] };
        }
        const passed: StudentRecord[] = [];
        const failed: StudentRecord[] = [];
        const absent: StudentRecord[] = [];

        for (const record of studentRecords!) {
            if (isStudentAbsent(record)) {
