                break;
            case 'absent':
                exportStudentListToExcel(absentStudents, 'Danh_Sach_Vang', reportDate);
                break;
            case 'master-list':
                if (studentRecords) exportMasterListToExcel(studentRecords, trainingUnits, reportDate);
                break;
            case 'audit':
