                        </div>
                    )}
                </div>
            ) : (
                <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden">
                    <div className="p-4 border-b dark:border-gray-700 bg-gray-50 dark:bg-gray-750">
                        <input type="text" placeholder="Tìm kiếm học viên..." className="w-full max-w-md px-4 py-2 border dark:border-gray-600 rounded-lg dark:bg-gray-700 dark:text-white" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                    </div>
                    {filteredHistory.length === 0 ? <div className="p-20 text-center text-gray-500 text-lg">Hệ thống không phát hiện sai sót trình tự hay trùng lắp môn thi.</div> : renderConflictTable(filteredHistory)}
                </div>
            )}
        </div>
    );
};

