    const handleExcelSubmit = async (rawRecords: StudentRecord[]) => {
        setIsLoading(true);
        setError(null);
        setConflicts([]);
        try {
            const cleanRecords = normalizeData(rawRecords);
            const processedData = processExcelData(cleanRecords);

            // Note: History check still uses full history, but we only have summaries in state.
            // We might need to fetch all sessions or just use what we have if local.
            // For now, assume history is needed.
            const allSessions = await storageService.getAllSessions();
            const detectedConflicts = checkHistoricalConflicts(cleanRecords, allSessions);

            setConflicts(detectedConflicts);
            setStudentRecords(cleanRecords);
            setAppData(processedData);
