interface StudentListReportProps {
    title: string;
    students: StudentRecord[];
    reportType: 'passed' | 'failed' | 'absent';
    reportDate: Date;
    trainingUnits?: TrainingUnit[];
    onStudentUpdate?: (id: string, field: string, value: any) => void;
