const { Pool } = require('pg');

const SERVER_VERSION = '3.9.2'; 
console.log(`\n\n==================================================`);
console.log(`🚀 STARTING SERVER v${SERVER_VERSION}`);
console.log(`==================================================\n`);

const app = express();
const port = process.env.PORT || 8080;

let pool = null;
let isDbConnected = false;
let connectionError = null;

const DB_CONFIG = {
    user: process.env.DB_USER || 'postgres',
    password: process.env.DB_PASSWORD || 'Appbaocao1!',
    database: process.env.DB_NAME || 'Appbaocao',
    instanceConnectionName: process.env.INSTANCE_CONNECTION_NAME || '',
    host: process.env.DB_HOST || '127.0.0.1',
    port: process.env.DB_PORT || 5432
};

const getPgConfig = () => {
    const baseConfig = {
        user: DB_CONFIG.user,
        password: DB_CONFIG.password,
        database: DB_CONFIG.database,
        max: 10,
        idleTimeoutMillis: 30000,
        connectionTimeoutMillis: 5000,
    };

    if (DB_CONFIG.instanceConnectionName) {
        // Cấu hình cho Google Cloud Run kết nối trực tiếp tới Cloud SQL qua Unix Socket
        console.log(`[DB] Cấu hình Unix Socket: /cloudsql/${DB_CONFIG.instanceConnectionName}`);
        return { 
            ...baseConfig, 
            host: `/cloudsql/${DB_CONFIG.instanceConnectionName}` 
        };
    } else {
        // Cấu hình cho Local hoặc External IP
        console.log(`[DB] Cấu hình TCP: ${DB_CONFIG.host}:${DB_CONFIG.port}`);
        return { 
            ...baseConfig, 
            host: DB_CONFIG.host, 
            port: parseInt(DB_CONFIG.port, 10) 
        };
    }
};

const initPool = async (retries = 3) => {
    try {
        const config = getPgConfig();
        if (pool) await pool.end(); // Đóng pool cũ nếu có

        pool = new Pool(config);

        // Kiểm tra kết nối bằng một query đơn giản
        const client = await pool.connect();
        const res = await client.query('SELECT NOW()');
        client.release();

        isDbConnected = true;
        connectionError = null;
        console.log("✅ Kết nối Database thành công lúc:", res.rows[0].now);
        await initSchema();
    } catch (err) {
        isDbConnected = false;
        connectionError = err.message;
        console.error("❌ Kết nối Database thất bại:", err.message);

        if (retries > 0) {
            console.log(`[DB] Đang thử lại sau 5 giây... (Còn ${retries} lần thử)`);
            setTimeout(() => initPool(retries - 1), 5000);
        }
    }
};

const initSchema = async () => {
    if (!pool || !isDbConnected) return;
    const queries = [
        `CREATE TABLE IF NOT EXISTS sessions (id VARCHAR(255) PRIMARY KEY, data JSONB NOT NULL, report_date TIMESTAMPTZ, created_at BIGINT);`,
        `CREATE TABLE IF NOT EXISTS training_units (id VARCHAR(255) PRIMARY KEY, code VARCHAR(50) NOT NULL, name VARCHAR(255) NOT NULL, created_at BIGINT);`
    ];
    try {
        for (let q of queries) await pool.query(q);
        console.log("✅ Cấu trúc bảng dữ liệu đã sẵn sàng.");
    } catch (err) {
        console.error("❌ Lỗi khởi tạo Schema:", err.message);
    }
};

initPool();

app.use(cors());
app.use(express.json({ limit: '50mb' }));

