import React, { ErrorInfo, ReactNode } from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

interface ErrorBoundaryProps {
    children?: ReactNode;
}

interface ErrorBoundaryState {
    hasError: boolean;
    error: Error | null;
}

// Error Boundary để bắt lỗi render
// FIX: Use React.Component explicitly and add a constructor to ensure 'this.props' is correctly typed and available in the class instance.
class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
    constructor(props: ErrorBoundaryProps) {
        super(props);
        this.state = {
            hasError: false,
            error: null
        };
    }

    static getDerivedStateFromError(error: Error): ErrorBoundaryState {
        return { hasError: true, error };
    }

    componentDidCatch(error: Error, errorInfo: ErrorInfo) {
        console.error("Uncaught error:", error, errorInfo);
    }

    render() {
        if (this.state.hasError) {
            return (
                <div className="flex flex-col items-center justify-center h-screen bg-red-50 text-red-800 p-6 text-center">
                    <h1 className="text-2xl font-bold mb-4">Đã xảy ra lỗi hệ thống</h1>
                    <p className="mb-4">Vui lòng tải lại trang hoặc liên hệ quản trị viên.</p>
                    <div className="bg-white p-4 rounded border border-red-200 text-xs text-left overflow-auto max-w-full mb-4 shadow-sm">
                        <strong>Error:</strong> {this.state.error?.toString()}
                    </div>
                    <button 
                        onClick={() => window.location.reload()}
                        className="px-6 py-2 bg-red-600 text-white font-bold rounded hover:bg-red-700 transition-colors"
                    >
                        <i className="fa-solid fa-rotate-right mr-2"></i> Tải lại trang
                    </button>
                </div>
            );
        }

        return this.props.children;
    }
}

