const express = require('express');
const cors = require('cors');
const path = require('path');
const { Pool } = require('pg');

const SERVER_VERSION = '4.0.0';
console.log(`\n\n[APPBCTH] Starting Server v${SERVER_VERSION}`);

const app = express();
const port = process.env.PORT || 8080;

let pool = null;
let isDbConnected = false;
let lastDbError = null;

const DB_CONFIG = {
    user: process.env.DB_USER || 'postgres',
    password: process.env.DB_PASSWORD || 'Appbaocao1!',
    database: process.env.DB_NAME || 'Appbaocao',
    instanceConnectionName: process.env.INSTANCE_CONNECTION_NAME || '', 
    host: process.env.DB_HOST || '127.0.0.1',
    port: process.env.DB_PORT || 5432
};

const connectWithRetry = async (retries = 5) => {
    const config = {
        user: DB_CONFIG.user,
        password: DB_CONFIG.password,
        database: DB_CONFIG.database,
        max: 15,
        idleTimeoutMillis: 30000,
        connectionTimeoutMillis: 5000,
    };

    if (DB_CONFIG.instanceConnectionName) {
        config.host = `/cloudsql/${DB_CONFIG.instanceConnectionName}`;
        console.log(`[DB] Using Cloud SQL Unix Socket: ${config.host}`);
    } else {
        config.host = DB_CONFIG.host;
        config.port = parseInt(DB_CONFIG.port, 10);
        console.log(`[DB] Using TCP Connection: ${config.host}:${config.port}`);
    }

    try {
        if (pool) await pool.end();
        pool = new Pool(config);

        const client = await pool.connect();
        await client.query('SELECT NOW()');
        client.release();

        isDbConnected = true;
        lastDbError = null;
        console.log("✅ [DB] PostgreSQL Connected Successfully.");
        await ensureSchema();
    } catch (err) {
        isDbConnected = false;
        lastDbError = err.message;
        console.error("❌ [DB] Connection Failed:", err.message);

        if (retries > 0) {
            console.log(`[DB] Retrying in 5s... (${retries} attempts left)`);
            setTimeout(() => connectWithRetry(retries - 1), 5000);
        }
    }
};

const ensureSchema = async () => {
    const schema = [
        `CREATE TABLE IF NOT EXISTS sessions (
            id VARCHAR(255) PRIMARY KEY, 
            data JSONB NOT NULL, 
            report_date TIMESTAMPTZ, 
            created_at BIGINT
        );`,
        `CREATE TABLE IF NOT EXISTS training_units (
            id VARCHAR(255) PRIMARY KEY, 
            code VARCHAR(50) NOT NULL, 
            name VARCHAR(255) NOT NULL, 
            created_at BIGINT
        );`
    ];
    try {
        for (let query of schema) await pool.query(query);
        console.log("✅ [DB] Schema Verified.");
    } catch (err) {
        console.error("❌ [DB] Schema Error:", err.message);
    }
};

connectWithRetry();

app.use(cors());
app.use(express.json({ limit: '50mb' }));

// Server & DB Status API
app.get('/api/server-status', (req, res) => {
    res.json({
        success: true,
        version: SERVER_VERSION,
        dbConnected: isDbConnected,
        dbError: lastDbError,
        env: process.env.NODE_ENV || 'production'
    });
});

app.post('/api/check-db-connection', async (req, res) => {
    await connectWithRetry(0);
    res.json({ success: isDbConnected, error: lastDbError });
});

// Sessions API
app.get('/api/sessions/summary', async (req, res) => {
    if (!isDbConnected) return res.status(503).json({ error: "Database offline" });
    try {
        const query = `
            SELECT id, data->>'name' as name, report_date as "reportDate", created_at as "createdAt",
            data->'grandTotal' as "grandTotal", jsonb_array_length(data->'studentRecords') as "studentCount"
            FROM sessions ORDER BY created_at DESC`;
        const result = await pool.query(query);
        res.json(result.rows);
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
});

app.get('/api/sessions/:id', async (req, res) => {
    if (!isDbConnected) return res.status(503).json({ error: "Database offline" });
    try {
        const result = await pool.query('SELECT data FROM sessions WHERE id = $1', [req.params.id]);
        if (result.rows.length === 0) return res.status(404).json({ error: 'Not found' });
        res.json(result.rows[0].data);
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
});

app.post('/api/sessions', async (req, res) => {
    if (!isDbConnected) return res.status(503).json({ error: "Database offline" });
    const session = req.body;
    try {
        await pool.query(
            `INSERT INTO sessions (id, data, report_date, created_at) VALUES ($1, $2, $3, $4) 
             ON CONFLICT (id) DO UPDATE SET data = EXCLUDED.data, report_date = EXCLUDED.report_date`,
            [session.id, JSON.stringify(session), session.reportDate, session.createdAt]
        );
        res.json({ success: true });
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
