const express = require('express');
const cors = require('cors');
const path = require('path');
const { Pool } = require('pg');

const SERVER_VERSION = '4.0.0';
console.log(`\n\n[APPBCTH] Starting Server v${SERVER_VERSION}`);

const app = express();
const port = process.env.PORT || 8080;

let pool = null;
let isDbConnected = false;
let lastDbError = null;

const DB_CONFIG = {
    user: process.env.DB_USER || 'postgres',
    password: process.env.DB_PASSWORD || 'Appbaocao1!',
    database: process.env.DB_NAME || 'Appbaocao',
    instanceConnectionName: process.env.INSTANCE_CONNECTION_NAME || '', 
    host: process.env.DB_HOST || '127.0.0.1',
    port: process.env.DB_PORT || 5432
};

const connectWithRetry = async (retries = 5) => {
    const config = {
        user: DB_CONFIG.user,
        password: DB_CONFIG.password,
        database: DB_CONFIG.database,
        max: 15,
        idleTimeoutMillis: 30000,
        connectionTimeoutMillis: 5000,
    };

    if (DB_CONFIG.instanceConnectionName) {
        config.host = `/cloudsql/${DB_CONFIG.instanceConnectionName}`;
        console.log(`[DB] Using Cloud SQL Unix Socket: ${config.host}`);
    } else {
        config.host = DB_CONFIG.host;
        config.port = parseInt(DB_CONFIG.port, 10);
        console.log(`[DB] Using TCP Connection: ${config.host}:${config.port}`);
    }

    try {
        if (pool) await pool.end();
        pool = new Pool(config);

        const client = await pool.connect();
        await client.query('SELECT NOW()');
        client.release();

        isDbConnected = true;
        lastDbError = null;
        console.log("✅ [DB] PostgreSQL Connected Successfully.");
        await ensureSchema();
    } catch (err) {
        isDbConnected = false;
        lastDbError = err.message;
        console.error("❌ [DB] Connection Failed:", err.message);

        if (retries > 0) {
            console.log(`[DB] Retrying in 5s... (${retries} attempts left)`);
            setTimeout(() => connectWithRetry(retries - 1), 5000);
        }
    }
};

const ensureSchema = async () => {
