const express = require('express');
const cors = require('cors');
const path = require('path');
const { Pool } = require('pg');

const SERVER_VERSION = '4.0.1';
console.log(`\n\n[APPBCTH] Starting Server v${SERVER_VERSION}`);

const app = express();
const port = process.env.PORT || 8080;

let pool = null;
let isDbConnected = false;
let lastDbError = null;

// Cấu hình Database từ biến môi trường
const DB_CONFIG = {
    user: process.env.DB_USER || 'postgres',
    password: process.env.DB_PASSWORD || 'Appbaocao1!',
    database: process.env.DB_NAME || 'Appbaocao',
    // Nếu chạy trên Google Cloud Run với Cloud SQL, hãy đặt biến này
    instanceConnectionName: process.env.INSTANCE_CONNECTION_NAME || '', 
    // Nếu kết nối qua IP (TCP), ưu tiên DB_HOST từ môi trường
    host: process.env.DB_HOST || '127.0.0.1',
    port: process.env.DB_PORT || 5432
};

const connectWithRetry = async (retries = 5) => {
    const config = {
        user: DB_CONFIG.user,
        password: DB_CONFIG.password,
        database: DB_CONFIG.database,
        max: 15,
        idleTimeoutMillis: 30000,
        connectionTimeoutMillis: 5000,
    };

    // Kiểm tra xem nên dùng Unix Socket hay TCP Host
    if (DB_CONFIG.instanceConnectionName && DB_CONFIG.instanceConnectionName !== '') {
        // Kết nối qua Unix Socket (Dành cho Google Cloud SQL)
        config.host = `/cloudsql/${DB_CONFIG.instanceConnectionName}`;
        console.log(`[DB] ⚡ Đang thử kết nối qua Unix Socket: ${config.host}`);
    } else {
        // Kết nối qua TCP (Dành cho Localhost hoặc IP Server)
        config.host = DB_CONFIG.host;
        config.port = parseInt(DB_CONFIG.port, 10);
        console.log(`[DB] 🌐 Đang thử kết nối qua TCP: ${config.host}:${config.port}`);
    }

    try {
        if (pool) {
            console.log("[DB] Đang đóng Pool cũ...");
            await pool.end().catch(() => {});
        }

        pool = new Pool(config);

        // Thử thực hiện một truy vấn nhỏ để xác nhận kết nối
        const client = await pool.connect();
        const res = await client.query('SELECT NOW()');
        client.release();

        isDbConnected = true;
        lastDbError = null;
        console.log("✅ [DB] Kết nối PostgreSQL THÀNH CÔNG lúc:", res.rows[0].now);
        await ensureSchema();
    } catch (err) {
        isDbConnected = false;
        lastDbError = err.message;

        console.error("❌ [DB] LỖI KẾT NỐI:");
        console.error(`   - Host: ${config.host}`);
        if (config.port) console.error(`   - Port: ${config.port}`);
        console.error(`   - Error: ${err.message}`);

        if (err.message.includes('ECONNREFUSED')) {
            console.error("   👉 GỢI Ý: PostgreSQL không phản hồi tại địa chỉ trên. Nếu bạn dùng Cloud SQL, hãy kiểm tra biến INSTANCE_CONNECTION_NAME.");
        }

        if (retries > 0) {
            console.log(`[DB] Sẽ thử lại sau 5 giây... (Còn ${retries} lần thử)`);
            setTimeout(() => connectWithRetry(retries - 1), 5000);
        }
    }
};

const ensureSchema = async () => {
    if (!pool) return;
    const schema = [
        `CREATE TABLE IF NOT EXISTS sessions (
            id VARCHAR(255) PRIMARY KEY, 
            data JSONB NOT NULL, 
            report_date TIMESTAMPTZ, 
            created_at BIGINT
        );`,
        `CREATE TABLE IF NOT EXISTS training_units (
            id VARCHAR(255) PRIMARY KEY, 
            code VARCHAR(50) NOT NULL, 
            name VARCHAR(255) NOT NULL, 
            created_at BIGINT
        );`
