import React, { Component, ErrorInfo, ReactNode } from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

interface Props { 
    // Fix: Make children optional to avoid JSX type mismatch in some TS versions
    children?: ReactNode; 
}
interface State { 
    hasError: boolean; 
    error: Error | null; 
}

// Fix: Import Component directly and extend it with Props and State generics to ensure state and props are properly typed.
class ErrorBoundary extends Component<Props, State> {
    constructor(props: Props) {
        super(props);
        // Fix: Properly initialize state in the constructor
        this.state = { hasError: false, error: null };
    }

    static getDerivedStateFromError(error: Error): State {
        return { hasError: true, error };
    }

    componentDidCatch(error: Error, info: ErrorInfo) {
        console.error("Uncaught error:", error, info);
    }

    render() {
        // Fix: Use the inherited state property which is now correctly recognized.
        if (this.state.hasError) {
            return (
                <div className="flex flex-col items-center justify-center h-screen bg-red-50 p-6 text-center">
                    <h1 className="text-2xl font-bold text-red-800 mb-4">Lỗi Hệ Thống APPBCTH</h1>
                    <div className="bg-white p-4 rounded border text-left text-xs font-mono max-w-xl overflow-auto mb-4">
                        {/* Fix: Access error property from state */}
                        {this.state.error?.toString()}
