const DB_HOST = (process.env.DB_HOST || '127.0.0.1').trim();
const DB_PORT = process.env.DB_PORT || 5432;

const connectWithRetry = async (retries = 5) => {
    // Cấu hình cơ bản
    const config = {
        user: DB_USER,
        password: DB_PASS,
        database: DB_NAME,
        max: 20,
        idleTimeoutMillis: 30000,
        connectionTimeoutMillis: 10000, // Tăng timeout để đợi socket sẵn sàng
    };

    // LOG QUAN TRỌNG ĐỂ KIỂM TRA BIẾN MÔI TRƯỜNG TRÊN CLOUD RUN
    console.log(`[DB-DEBUG] Checking Connection Strategy...`);
    console.log(`[DB-DEBUG] INSTANCE_CONNECTION_NAME: "${INSTANCE_NAME}"`);

    if (INSTANCE_NAME !== '') {
        // KẾT NỐI QUA UNIX SOCKET (BẮT BUỘC CHO CLOUD SQL TRÊN CLOUD RUN)
        config.host = `/cloudsql/${INSTANCE_NAME}`;
        console.log(`[DB] ⚡ Chế độ: Cloud SQL (Unix Socket)`);
        console.log(`[DB] 📍 Path: ${config.host}`);
    } else {
        // KẾT NỐI QUA TCP (CHỈ DÙNG KHI TEST LOCAL HOẶC CÓ IP RIÊNG)
        config.host = DB_HOST;
        config.port = parseInt(DB_PORT, 10);
        console.log(`[DB] 🌐 Chế độ: TCP/IP (Local hoặc External IP)`);
        console.log(`[DB] 📍 Host: ${config.host}:${config.port}`);
    }

    try {
        if (pool) {
            await pool.end().catch(() => {});
        }

        pool = new Pool(config);

        // Kiểm tra kết nối thực tế
        const client = await pool.connect();
        const res = await client.query('SELECT NOW()');
        client.release();

        isDbConnected = true;
        lastDbError = null;
        console.log("✅ [DB] KẾT NỐI THÀNH CÔNG.");
        await ensureSchema();
    } catch (err) {
        isDbConnected = false;
        lastDbError = err.message;

        console.error("❌ [DB] LỖI KẾT NỐI CHI TIẾT:");
        console.error(`   - Thông báo: ${err.message}`);

        if (err.message.includes('ECONNREFUSED')) {
            console.error(`   - Chú ý: Lỗi ECONNREFUSED trên 127.0.0.1 cho thấy INSTANCE_CONNECTION_NAME đang bị trống hoặc sai.`);
