// FIX: Explicitly extending React.Component and providing generic Props and State interfaces to ensure that 'props' and 'state' are correctly typed and recognized by the TypeScript compiler.
class ErrorBoundary extends React.Component<Props, State> {
    // FIX: Initialize state as a class property for better compatibility with strict TypeScript configurations.
    public state: State = { hasError: false, error: null };

    constructor(props: Props) {
        super(props);
    }

