import type { StudentRecord, TrainingUnit, SavedSession, ConflictWarning } from '../types';

// Helper chuẩn hóa ID để so khớp (Loại bỏ số 0 ở đầu, khoảng trắng)
const normalizeIdForMatch = (id: string | number | undefined): string => {
    if (id === undefined || id === null) return '';
    return String(id).trim().toUpperCase().replace(/^0+/, '');
};

export const getResultStatus = (result: string | number | undefined | null): { participated: boolean, passed: boolean } => {
    if (result === undefined || result === null) return { participated: false, passed: false };
    const normalized = result.toString().trim().toUpperCase();
    if (normalized === '' || normalized === 'VẮNG' || normalized === 'V') return { participated: false, passed: false };
    const isPassed = normalized === 'ĐẠT' || normalized === 'PASSED' || normalized === 'P' || normalized === '1' || normalized === 'CHẠM';
    return { participated: true, passed: isPassed };
};

export const isStudentAbsent = (record: StudentRecord): boolean => {
    const theory = getResultStatus(record['LÝ THUYẾT']);
    const simulation = getResultStatus(record['MÔ PHỎNG']);
    const practical = getResultStatus(record['SA HÌNH']);
    const onRoad = getResultStatus(record['ĐƯỜNG TRƯỜNG']);
    return !theory.participated && !simulation.participated && !practical.participated && !onRoad.participated;
};

export const isStudentPassed = (record: StudentRecord): boolean => {
    if (isStudentAbsent(record)) return false;

    let noiDungThi = (record['NỘI DUNG THI'] || '').toString().trim().toUpperCase();
    noiDungThi = noiDungThi.replace(/Đ/g, 'D');

    if (noiDungThi.length === 0) return false;

    const requiredTestsPassed =
        (!noiDungThi.includes('L') || getResultStatus(record['LÝ THUYẾT']).passed) &&
        (!noiDungThi.includes('M') || getResultStatus(record['MÔ PHỎNG']).passed) &&
        (!noiDungThi.includes('H') || getResultStatus(record['SA HÌNH']).passed) &&
        (!noiDungThi.includes('D') || getResultStatus(record['ĐƯỜNG TRƯỜNG']).passed);

    return requiredTestsPassed;
};

const getPartName = (code: string) => {
    switch(code) {
        case 'L': return 'Lý thuyết';
        case 'M': return 'Mô phỏng';
        case 'H': return 'Sa hình';
        case 'D': return 'Đường trường';
        default: return code;
    }
};

const PART_ORDER = ['L', 'M', 'H', 'D'];

export const checkHistoricalConflicts = (
    currentRecords: StudentRecord[],
    history: SavedSession[]
): ConflictWarning[] => {
    const warnings: ConflictWarning[] = [];

    // Bản đồ lưu thông tin theo Mã HV (Đã chuẩn hóa) và CCCD
    const studentHistory = new Map<string, {
        passed: Set<string>,
        failed: Set<string>,
        firstFramework: Set<string>,
        lastSession: { name: string, date: string }
    }>();

    // Sắp xếp lịch sử theo thời gian
    const sortedHistory = [...history].sort((a, b) => 
        new Date(a.reportDate).getTime() - new Date(b.reportDate).getTime()
    );

    // BƯỚC 1: Thu thập toàn bộ lịch sử
    sortedHistory.forEach(session => {
        const sessionDate = new Date(session.reportDate).toLocaleDateString('vi-VN');

        session.studentRecords.forEach(record => {
            const sid = normalizeIdForMatch(record['MÃ HỌC VIÊN']);
            const cccd = normalizeIdForMatch(record['SỐ CHỨNG MINH']);
            if (!sid && !cccd) return;

            // Sử dụng SID làm key chính, fallback CCCD
            const key = sid || `cccd-${cccd}`;

            if (!studentHistory.has(key)) {
                studentHistory.set(key, {
                    passed: new Set(),
                    failed: new Set(),
                    firstFramework: new Set(),
                    lastSession: { name: session.name, date: sessionDate }
                });
            }

            const historyData = studentHistory.get(key)!;
            historyData.lastSession = { name: session.name, date: sessionDate };

            // Ghi nhận bộ khung lần đầu
            if (historyData.firstFramework.size === 0) {
                const content = String(record['NỘI DUNG THI'] || '').toUpperCase().replace(/Đ/g, 'D');
                PART_ORDER.forEach(p => { if (content.includes(p)) historyData.firstFramework.add(p); });
            }

            // Cập nhật trạng thái Đạt/Trượt
            const subjects = [
                { code: 'L', val: record['LÝ THUYẾT'] },
                { code: 'M', val: record['MÔ PHỎNG'] },
                { code: 'H', val: record['SA HÌNH'] },
                { code: 'D', val: record['ĐƯỜNG TRƯỜNG'] }
            ];

            subjects.forEach(sub => {
                const status = getResultStatus(sub.val);
                if (status.participated) {
                    if (status.passed) {
                        historyData.passed.add(sub.code);
                        historyData.failed.delete(sub.code);
                    } else {
                        // Chỉ coi là trượt nếu chưa từng đỗ
                        if (!historyData.passed.has(sub.code)) {
                            historyData.failed.add(sub.code);
                        }
                    }
                }
            });
        });
    });

    // BƯỚC 2: Đối soát dữ liệu hiện tại
    currentRecords.forEach(record => {
        const sid = normalizeIdForMatch(record['MÃ HỌC VIÊN']);
        const cccd = normalizeIdForMatch(record['SỐ CHỨNG MINH']);
        const key = sid || `cccd-${cccd}`;

        const historyData = studentHistory.get(key);
        if (!historyData) return;

        const currentContent = String(record['NỘI DUNG THI'] || '').toUpperCase().replace(/Đ/g, 'D');
        const currentParts = new Set<string>();
        PART_ORDER.forEach(p => { if (currentContent.includes(p)) currentParts.add(p); });

        // 1. Kiểm tra thi lại môn đã đỗ
        currentParts.forEach(p => {
            if (historyData.passed.has(p)) {
                warnings.push({
                    studentName: record['HỌ VÀ TÊN'],
                    studentId: String(record['MÃ HỌC VIÊN']),
                    conflictPart: `Môn ${getPartName(p)} đã ĐẠT trong quá khứ`,
                    previousSessionName: historyData.lastSession.name,
                    previousDate: historyData.lastSession.date
                });
            }
        });

        // 2. Kiểm tra thi thiếu môn (Từng trượt nhưng lần này không đăng ký)
        historyData.failed.forEach(p => {
            if (!currentParts.has(p)) {
                warnings.push({
                    studentName: record['HỌ VÀ TÊN'],
                    studentId: String(record['MÃ HỌC VIÊN']),
                    conflictPart: `Thi thiếu môn: Thí sinh từng TRƯỢT ${getPartName(p)} nhưng kỳ này không đăng ký thi lại`,
                    previousSessionName: historyData.lastSession.name,
                    previousDate: historyData.lastSession.date
                });
            }
        });

        // 3. Kiểm tra môn nằm ngoài bộ khung ban đầu
        currentParts.forEach(p => {
            if (historyData.firstFramework.size > 0 && !historyData.firstFramework.has(p)) {
                warnings.push({
                    studentName: record['HỌ VÀ TÊN'],
                    studentId: String(record['MÃ HỌC VIÊN']),
                    conflictPart: `Sai bộ khung: Môn ${getPartName(p)} không có trong nội dung đăng ký lần đầu`,
                    previousSessionName: historyData.lastSession.name,
                    previousDate: historyData.lastSession.date
                });
            }
        });
    });

    return warnings;
};

export const generateClassSummaryString = (students: StudentRecord[]): string => {
    if (!students || students.length === 0) return "Tổng số: 0";
    const classCounts: { [key: string]: number } = {};
    for (const student of students) {
        const className = String(student['HẠNG GPLX'] || 'Khác').trim();
        classCounts[className] = (classCounts[className] || 0) + 1;
    }
    const sortedClasses = Object.keys(classCounts).sort();
    const parts = sortedClasses.map(className => `Hạng ${className}: ${classCounts[className]}`);
    return `Tổng số: ${students.length}\u00A0\u00A0\u00A0\u00A0${parts.join('; ')}`;
};

export const generateGhiChu = (record: StudentRecord): string => {
    const maHocVien = (record['MÃ HỌC VIÊN'] || '').toString().trim();
    const isRetake = maHocVien.startsWith('2721') || maHocVien.startsWith('2722');

    let testsTaken = (record['NỘI DUNG THI'] || '').toString().trim().toUpperCase();
    if (isRetake) return `Thi lại: ${testsTaken}`;
    return `Thi lần đầu`;
};

export const identifyTrainingUnit = (studentId: string | number | undefined, units: TrainingUnit[] = []): string => {
    if (!studentId || !units || units.length === 0) return '';
    const sId = studentId.toString().trim();
    const sortedUnits = [...units].sort((a, b) => b.code.length - a.code.length);
    const matchedUnit = sortedUnits.find(u => sId.startsWith(u.code));
    return matchedUnit ? matchedUnit.name : '';
};

import type { AppData, LicenseClassData, StudentRecord } from '../types';
import { getResultStatus, isStudentAbsent, isStudentPassed } from './reportUtils';

export const normalizeRecord = (record: any): StudentRecord => {
    const normalized: any = {};
    // Mở rộng bộ keyMap để nhận diện thông minh hơn
    const keyMap: {[key: string]: string} = {
        'SỐ BÁO DANH': 'SỐ BÁO DANH', 'SBD': 'SỐ BÁO DANH', 'SO BAO DANH': 'SỐ BÁO DANH', 'SỐ BD': 'SỐ BÁO DANH',
        'MÃ HỌC VIÊN': 'MÃ HỌC VIÊN', 'MÃ HV': 'MÃ HỌC VIÊN', 'MAHV': 'MÃ HỌC VIÊN', 'MADK': 'MÃ HỌC VIÊN', 'MÃ ĐK': 'MÃ HỌC VIÊN', 'MÃ SỐ': 'MÃ HỌC VIÊN', 'MA SO': 'MÃ HỌC VIÊN',
        'HỌ VÀ TÊN': 'HỌ VÀ TÊN', 'HO VA TEN': 'HỌ VÀ TÊN', 'HỌ TÊN': 'HỌ VÀ TÊN', 'TÊN': 'HỌ VÀ TÊN', 'TEN HOC VIEN': 'HỌ VÀ TÊN',
        'HẠNG GPLX': 'HẠNG GPLX', 'HẠNG': 'HẠNG GPLX', 'HANG': 'HẠNG GPLX', 'HANG XE': 'HẠNG GPLX', 'HẠNG ĐĂNG KÝ': 'HẠNG GPLX',
        'NỘI DUNG THI': 'NỘI DUNG THI', 'ND THI': 'NỘI DUNG THI', 'NDSH': 'NỘI DUNG THI', 'NỘI DUNG': 'NỘI DUNG THI',
        'LÝ THUYẾT': 'LÝ THUYẾT', 'LT': 'LÝ THUYẾT', 'LY THUYET': 'LÝ THUYẾT', 'ĐIỂM LT': 'LÝ THUYẾT', 'KQ LT': 'LÝ THUYẾT',
        'MÔ PHỎNG': 'MÔ PHỎNG', 'MP': 'MÔ PHỎNG', 'MO PHONG': 'MÔ PHỎNG', 'ĐIỂM MP': 'MÔ PHỎNG', 'KQ MP': 'MÔ PHỎNG',
        'SA HÌNH': 'SA HÌNH', 'SH': 'SA HÌNH', 'SA HINH': 'SA HÌNH', 'TH TRONG HÌNH': 'SA HÌNH', 'KQ SH': 'SA HÌNH',
        'ĐƯỜNG TRƯỜNG': 'ĐƯỜNG TRƯỜNG', 'ĐT': 'ĐƯỜNG TRƯỜNG', 'DT': 'ĐƯỜNG TRƯỜNG', 'KQ ĐT': 'ĐƯỜNG TRƯỜNG', 'TH ĐƯỜNG TRƯỜNG': 'ĐƯỜNG TRƯỜNG',
        'SỐ CHỨNG MINH': 'SỐ CHỨNG MINH', 'CCCD': 'SỐ CHỨNG MINH', 'CMND': 'SỐ CHỨNG MINH', 'SỐ THẺ': 'SỐ CHỨNG MINH',
        'NGÀY SINH': 'NGÀY SINH', 'NGAY SINH': 'NGÀY SINH', 'NS': 'NGÀY SINH',
        'NƠI CƯ TRÚ': 'NƠI CƯ TRÚ', 'DIA CHI': 'NƠI CƯ TRÚ', 'HỘ KHẨU': 'NƠI CƯ TRÚ', 'TRÚ QUÁN': 'NƠI CƯ TRÚ'
    };

    Object.keys(record).forEach(key => {
        const cleanKey = key.trim().toUpperCase().replace(/\s+/g, ' ');
        const mapped = keyMap[cleanKey] || cleanKey;
        normalized[mapped] = record[key];
    });

    // Tự động suy luận nội dung thi nếu thiếu
    if (!normalized['NỘI DUNG THI']) {
        const parts = [];
        if (normalized['LÝ THUYẾT'] !== undefined && normalized['LÝ THUYẾT'] !== '') parts.push('L');
        if (normalized['MÔ PHỎNG'] !== undefined && normalized['MÔ PHỎNG'] !== '') parts.push('M');
        if (normalized['SA HÌNH'] !== undefined && normalized['SA HÌNH'] !== '') parts.push('H');
        if (normalized['ĐƯỜNG TRƯỜNG'] !== undefined && normalized['ĐƯỜNG TRƯỜNG'] !== '') parts.push('Đ');
        normalized['NỘI DUNG THI'] = parts.join('+');
    }

    return normalized as StudentRecord;
};

const createEmptyClass = (className: string): LicenseClassData => ({
    class: className,
    totalApplications: 0,
    totalParticipants: 0,
    theory: { total: 0, pass: 0, fail: 0 },
    simulation: { total: 0, pass: 0, fail: 0 },
    practicalCourse: { total: 0, pass: 0, fail: 0 },
    onRoad: { total: 0, pass: 0, fail: 0 },
    finalPass: 0,
});

export const normalizeData = (raw: any[]): StudentRecord[] => raw.map(normalizeRecord);

export const processExcelData = (rawRecords: StudentRecord[]): AppData => {
    const firstTime: Record<string, LicenseClassData> = {};
    const retake: Record<string, LicenseClassData> = {};

    rawRecords.forEach(record => {
        const className = String(record['HẠNG GPLX'] || '').trim();
        if (!className) return;

        const maHV = String(record['MÃ HỌC VIÊN'] || '').trim();
        const isRetake = maHV.startsWith('2721') || maHV.startsWith('2722');
        const target = isRetake ? retake : firstTime;

        if (!target[className]) target[className] = createEmptyClass(className);
        const data = target[className];

        data.totalApplications++;
        if (!isStudentAbsent(record)) data.totalParticipants++;

        // Subject stats
        const lt = getResultStatus(record['LÝ THUYẾT']);
        if (lt.participated) { data.theory.total++; if (lt.passed) data.theory.pass++; }

        const mp = getResultStatus(record['MÔ PHỎNG']);
        if (mp.participated) { data.simulation.total++; if (mp.passed) data.simulation.pass++; }

        const sh = getResultStatus(record['SA HÌNH']);
        if (sh.participated) { data.practicalCourse.total++; if (sh.passed) data.practicalCourse.pass++; }

        const dt = getResultStatus(record['ĐƯỜNG TRƯỜNG']);
        if (dt.participated) { data.onRoad.total++; if (dt.passed) data.onRoad.pass++; }

        if (isStudentPassed(record)) data.finalPass++;
    });

    const finalize = (obj: Record<string, LicenseClassData>) => 
        Object.values(obj)
            .map(v => ({
                ...v,
                theory: { ...v.theory, fail: Math.max(0, v.theory.total - v.theory.pass) },
                simulation: { ...v.simulation, fail: Math.max(0, v.simulation.total - v.simulation.pass) },
                practicalCourse: { ...v.practicalCourse, fail: Math.max(0, v.practicalCourse.total - v.practicalCourse.pass) },
                onRoad: { ...v.onRoad, fail: Math.max(0, v.onRoad.total - v.onRoad.pass) }
            }))
            .sort((a, b) => a.class.localeCompare(b.class));

    return {
        firstTime: { title: 'a) Học viên dự thi lần đầu:', rows: finalize(firstTime) },
        retake: { title: 'b) Thí sinh thuộc đối tượng cấp lại giấy phép lái xe và thí sinh tự do:', rows: finalize(retake) }
    };
};

