// FIX: Implement exportUnitStatisticsToExcel for unit-based reporting
export const exportUnitStatisticsToExcel = (students: StudentRecord[], trainingUnits: TrainingUnit[], reportDate: Date) => {
    const wb = XLSX.utils.book_new();
    const data: Record<string, any> = {};

    students.forEach(student => {
        const unitName = identifyTrainingUnit(student['MÃ HỌC VIÊN'], trainingUnits) || 'Thí sinh tự do / Khác';
        if (!data[unitName]) {
            data[unitName] = { 
                'Đơn vị': unitName, 'Tổng số': 0, 'Đạt': 0, 'Trượt': 0, 'Vắng': 0,
                'Lý thuyết': 0, 'Mô phỏng': 0, 'Sa hình': 0, 'Đường trường': 0
            };
        }
        data[unitName]['Tổng số']++;
        if (isStudentAbsent(student)) data[unitName]['Vắng']++;
        else if (isStudentPassed(student)) data[unitName]['Đạt']++;
        else data[unitName]['Trượt']++;

        if (getResultStatus(student['LÝ THUYẾT']).passed) data[unitName]['Lý thuyết']++;
        if (getResultStatus(student['MÔ PHỎNG']).passed) data[unitName]['Mô phỏng']++;
        if (getResultStatus(student['SA HÌNH']).passed) data[unitName]['Sa hình']++;
        if (getResultStatus(student['ĐƯỜNG TRƯỜNG']).passed) data[unitName]['Đường trường']++;
    });

    const ws = XLSX.utils.json_to_sheet(Object.values(data));
    XLSX.utils.book_append_sheet(wb, ws, "ThongKeDonVi");
    XLSX.writeFile(wb, `Thong_Ke_Don_Vi_${formatDateForFilename(reportDate)}.xlsx`);
};

// FIX: Implement exportMasterListToExcel for comprehensive detailed list
export const exportMasterListToExcel = (students: StudentRecord[], trainingUnits: TrainingUnit[], reportDate: Date) => {
    const wb = XLSX.utils.book_new();
    const data = students.map((s, idx) => ({
        'STT': idx + 1,
        'SỐ BÁO DANH': s['SỐ BÁO DANH'],
        'HỌ VÀ TÊN': s['HỌ VÀ TÊN'],
        'NGÀY SINH': s['NGÀY SINH'],
        'HẠNG': s['HẠNG GPLX'],
        'ĐƠN VỊ ĐÀO TẠO': identifyTrainingUnit(s['MÃ HỌC VIÊN'], trainingUnits),
        'LÝ THUYẾT': s['LÝ THUYẾT'],
        'MÔ PHỎNG': s['MÔ PHỎNG'],
        'SA HÌNH': s['SA HÌNH'],
        'ĐƯỜNG TRƯỜNG': s['ĐƯỜNG TRƯỜNG'],
        'KẾT QUẢ': isStudentAbsent(s) ? 'VẮNG' : (isStudentPassed(s) ? 'ĐẠT' : 'TRƯỢT')
    }));
    const ws = XLSX.utils.json_to_sheet(data);
    XLSX.utils.book_append_sheet(wb, ws, "TongHopChiTiet");
    XLSX.writeFile(wb, `Tong_Hop_Chi_Tiet_${formatDateForFilename(reportDate)}.xlsx`);
};

// FIX: Implement exportAggregateReportToExcel for periodic reporting across sessions
export const exportAggregateReportToExcel = (sessions: SavedSession[], totals: any, title: string) => {
    const wb = XLSX.utils.book_new();
    const data = sessions.map((s, idx) => ({
        'STT': idx + 1,
        'Tên Kỳ Sát Hạch': s.name,
        'Ngày': new Date(s.reportDate).toLocaleDateString('vi-VN'),
        'Lý Thuyết': s.grandTotal.theory.total,
        'Mô Phỏng': s.grandTotal.simulation.total,
        'Sa Hình': s.grandTotal.practicalCourse.total,
        'Đường Trường': s.grandTotal.onRoad.total,
        'Tổng Đạt': s.grandTotal.finalPass
    }));

    // Add totals row
    data.push({
        'STT': null,
        'Tên Kỳ Sát Hạch': 'TỔNG CỘNG',
        'Ngày': null,
        'Lý Thuyết': totals.theory,
        'Mô Phỏng': totals.simulation,
        'Sa Hình': totals.practical,
        'Đường Trường': totals.road,
        'Tổng Đạt': totals.pass
    } as any);

    const ws = XLSX.utils.json_to_sheet(data);
    XLSX.utils.book_append_sheet(wb, ws, "BaoCaoTongHopLuotThi");
    XLSX.writeFile(wb, `Bao_Cao_Tong_Hop_${title.replace(/\//g, '-')}.xlsx`);
};

import React, { useMemo } from 'react';
import type { LicenseClassData, ReportMetadata } from '../../types';
import { toVietnameseWords } from '../../services/vietnameseNumberToWords';

interface FeeSummaryReportProps {
    grandTotal: LicenseClassData | null;
    reportMetadata: ReportMetadata;
    reportDate: Date;
}

const formatCurrency = (value: number) => {
    return value.toLocaleString('vi-VN');
};

const BASE_FEE_RATES = {
    theory: 100000,
    simulation: 100000,
    practicalCourse: 350000,
    onRoad: 80000,
};

export const FeeSummaryReport: React.FC<FeeSummaryReportProps> = ({ grandTotal, reportMetadata, reportDate }) => {
    // Xác định đơn giá lệ phí cấp GPLX dựa trên ngày báo cáo
    const licensingFeeRate = useMemo(() => {
        // Tạo mốc thời gian 01/01/2026 (giờ địa phương) để so sánh chính xác
        const thresholdDate = new Date(2026, 0, 1); 
        return reportDate >= thresholdDate ? 115000 : 135000;
    }, [reportDate]);

    const feeData = useMemo(() => {
        if (!grandTotal) return null;

        const theoryTotal = grandTotal.theory.total * BASE_FEE_RATES.theory;
        const simulationTotal = grandTotal.simulation.total * BASE_FEE_RATES.simulation;
        const practicalCourseTotal = grandTotal.practicalCourse.total * BASE_FEE_RATES.practicalCourse;
        const onRoadTotal = grandTotal.onRoad.total * BASE_FEE_RATES.onRoad;

        // Tính tiền lệ phí cấp GPLX dựa trên số người đạt sau cùng (finalPass)
        const licensingTotal = grandTotal.finalPass * licensingFeeRate;

        const totalExaminationFee = theoryTotal + simulationTotal + practicalCourseTotal + onRoadTotal;
        const grandTotalFee = totalExaminationFee + licensingTotal;

        return {
            theory: { count: grandTotal.theory.total, total: theoryTotal },
            simulation: { count: grandTotal.simulation.total, total: simulationTotal },
            practicalCourse: { count: grandTotal.practicalCourse.total, total: practicalCourseTotal },
            onRoad: { count: grandTotal.onRoad.total, total: onRoadTotal },
            licensing: { count: grandTotal.finalPass, total: licensingTotal },
            totalExaminationFee,
            grandTotalFee,
        };
    }, [grandTotal, licensingFeeRate]);

    if (!grandTotal || !feeData) {
        return null;
    }

    const passRate = grandTotal.totalParticipants > 0 ? (grandTotal.finalPass / grandTotal.totalParticipants) * 100 : 0;
    const theoryPassRate = grandTotal.theory.total > 0 ? (grandTotal.theory.pass / grandTotal.theory.total) * 100 : 0;
    const simulationPassRate = grandTotal.simulation.total > 0 ? (grandTotal.simulation.pass / grandTotal.simulation.total) * 100 : 0;
    const practicalCoursePassRate = grandTotal.practicalCourse.total > 0 ? (grandTotal.practicalCourse.pass / grandTotal.practicalCourse.total) * 100 : 0;
    const onRoadPassRate = grandTotal.onRoad.total > 0 ? (grandTotal.onRoad.pass / grandTotal.onRoad.total) * 100 : 0;

    const tableCellStyle = "p-2 border border-black text-center text-sm";
    const tableHeaderCellStyle = `${tableCellStyle} font-bold`;
    const sectionCellStyle = `${tableCellStyle} font-bold text-left`;
    const totalRowCellStyle = `${tableCellStyle} font-bold`;

    return (
        <section className="mt-8 text-sm sm:text-base select-none">
            <div className="space-y-1">
                <p>
                    Như vậy tổng số thí sinh trúng tuyển được đề nghị cấp GPLX là: <strong>{grandTotal.finalPass}</strong> thí sinh; Đạt tỷ lệ: <strong>{passRate.toFixed(2)}%</strong>
                </p>
                <p className="pl-4">
                    (Trong đó thi lý thuyết là: {theoryPassRate.toFixed(2)}%; thi mô phỏng là: {simulationPassRate.toFixed(2)}%; thi thực hành trong hình là: {practicalCoursePassRate.toFixed(2)}%; thi thực hành trên đường là: {onRoadPassRate.toFixed(2)}%)
                </p>
            </div>
            <div className="mt-4">
                <h3 className="font-bold">II. Nhận xét kỳ sát hạch:</h3>
                <ul className="list-inside mt-2 space-y-1 pl-4">
                    <li>- Kỳ thi được thực hiện đúng quy chế và nghiêm túc, không có trường hợp nào giám khảo và thí sinh vi phạm nội quy, quy chế thi.</li>
                    <li>- Đội ngũ cán bộ sát hạch có trình độ và nghiệp vụ, trong quá trình tổ chức thi thực hiện đúng chức trách;</li>
                    <li>- Cơ sở vật chất kỹ thuật phục vụ kỳ thi chuẩn bị tốt, cán bộ cơ sở chu đáo, nhiệt tình.</li>
                    <li>- Giữa Hội đồng, CS Đào tạo và TT Sát hạch có sự phối hợp chặt chẽ thực hiện kỳ thi đảm bảo an toàn.</li>
                    {reportMetadata.technicalErrorSBD && (
                        <li>- Xét lỗi kỹ thuật: SBD : {reportMetadata.technicalErrorSBD}</li>
                    )}
                </ul>
            </div>

            <div className="mt-4">
                 <h3 className="font-bold">III. Tổng hợp số thu phí sát hạch và lệ phí cấp GPLX:</h3>
                 <table className="w-full border-collapse border border-black mt-2">
                    <thead>
                        <tr>
                            <th className={tableHeaderCellStyle}>STT</th>
                            <th className={tableHeaderCellStyle}>Nội Dung</th>
                            <th className={tableHeaderCellStyle}>Số Lượng</th>
                            <th className={tableHeaderCellStyle}>Mỗi Thí Sinh Nộp</th>
                            <th className={tableHeaderCellStyle}>Thành Tiền</th>
                        </tr>
                    </thead>
                    <tbody>
                        <tr>
                            <td className={`${sectionCellStyle} text-center` }>I</td>
                            <td className={sectionCellStyle}>Phí Sát Hạch Lái Xe</td>
                            <td className={tableCellStyle}></td>
                            <td className={tableCellStyle}></td>
                            <td className={`${totalRowCellStyle} text-right pr-4`}>{formatCurrency(feeData.totalExaminationFee)}</td>
                        </tr>
                        <tr>
                            <td className={tableCellStyle}>1</td>
                            <td className={`${tableCellStyle} text-left`}>Lý Thuyết</td>
                            <td className={tableCellStyle}>{feeData.theory.count}</td>
                            <td className={`${tableCellStyle} text-right pr-4`}>{formatCurrency(BASE_FEE_RATES.theory)}</td>
                            <td className={`${tableCellStyle} text-right pr-4`}>{formatCurrency(feeData.theory.total)}</td>
                        </tr>
                        <tr>
                            <td className={tableCellStyle}>2</td>
                            <td className={`${tableCellStyle} text-left`}>Mô phỏng các tình huống giao thông</td>
                            <td className={tableCellStyle}>{feeData.simulation.count}</td>
                            <td className={`${tableCellStyle} text-right pr-4`}>{formatCurrency(BASE_FEE_RATES.simulation)}</td>
                            <td className={`${tableCellStyle} text-right pr-4`}>{formatCurrency(feeData.simulation.total)}</td>
                        </tr>
                         <tr>
                            <td className={tableCellStyle}>3</td>
                            <td className={`${tableCellStyle} text-left`}>Thực hành trong hình</td>
                            <td className={tableCellStyle}>{feeData.practicalCourse.count}</td>
                            <td className={`${tableCellStyle} text-right pr-4`}>{formatCurrency(BASE_FEE_RATES.practicalCourse)}</td>
                            <td className={`${tableCellStyle} text-right pr-4`}>{formatCurrency(feeData.practicalCourse.total)}</td>
                        </tr>
                        <tr>
                            <td className={tableCellStyle}>4</td>
                            <td className={`${tableCellStyle} text-left`}>Thực hành trên đường giao thông</td>
                            <td className={tableCellStyle}>{feeData.onRoad.count}</td>
                            <td className={`${tableCellStyle} text-right pr-4`}>{formatCurrency(BASE_FEE_RATES.onRoad)}</td>
                            <td className={`${tableCellStyle} text-right pr-4`}>{formatCurrency(feeData.onRoad.total)}</td>
                        </tr>
                         <tr className="bg-yellow-50/30">
                            <td className={`${sectionCellStyle} text-center`}>II</td>
                            <td className={sectionCellStyle}>Lệ phí cấp Giấy phép lái xe</td>
                            <td className={tableCellStyle}>{feeData.licensing.count}</td>
                            <td className={`${tableCellStyle} text-right pr-4 font-bold text-blue-600`}>{formatCurrency(licensingFeeRate)}</td>
                            <td className={`${tableCellStyle} text-right pr-4`}>{formatCurrency(feeData.licensing.total)}</td>
                        </tr>
                        <tr>
                            <td colSpan={4} className={`${totalRowCellStyle} text-center bg-gray-100`}>Tổng phí sát hạch (I+II)</td>
                            <td className={`${totalRowCellStyle} text-right pr-4 bg-gray-100`}>{formatCurrency(feeData.grandTotalFee)}</td>
                        </tr>
                        <tr>
                            <td colSpan={5} className={`${tableCellStyle} text-left`}>
                                <strong>Bằng Chữ:</strong> {toVietnameseWords(feeData.grandTotalFee)}
                            </td>
                        </tr>
                    </tbody>
                 </table>
            </div>
        </section>
    );
};

