export const exportUnitStatisticsToExcel = (students: StudentRecord[], trainingUnits: TrainingUnit[], reportDate: Date) => {
    const wb = XLSX.utils.book_new();
    const data: Record<string, any> = {};

    students.forEach(student => {
        const unitName = identifyTrainingUnit(student['MÃ HỌC VIÊN'], trainingUnits) || 'Thí sinh tự do / Khác';
        if (!data[unitName]) {
            data[unitName] = { 
                'Đơn vị': unitName, 'Tổng số': 0, 'Đạt': 0, 'Trượt': 0, 'Vắng': 0,
                'Lý thuyết': 0, 'Mô phỏng': 0, 'Sa hình': 0, 'Đường trường': 0
            };
        }
        data[unitName]['Tổng số']++;
        if (isStudentAbsent(student)) data[unitName]['Vắng']++;
        else if (isStudentPassed(student)) data[unitName]['Đạt']++;
        else data[unitName]['Trượt']++;

        if (getResultStatus(student['LÝ THUYẾT']).passed) data[unitName]['Lý thuyết']++;
        if (getResultStatus(student['MÔ PHỎNG']).passed) data[unitName]['Mô phỏng']++;
        if (getResultStatus(student['SA HÌNH']).passed) data[unitName]['Sa hình']++;
        if (getResultStatus(student['ĐƯỜNG TRƯỜNG']).passed) data[unitName]['Đường trường']++;
    });

    const ws = XLSX.utils.json_to_sheet(Object.values(data));
    XLSX.utils.book_append_sheet(wb, ws, "ThongKeDonVi");
    XLSX.writeFile(wb, `Thong_Ke_Don_Vi_${formatDateForFilename(reportDate)}.xlsx`);
};

