    const licensingFeeRate = useMemo(() => {
        // Tạo mốc thời gian 01/01/2026 (giờ địa phương) để so sánh chính xác
        const thresholdDate = new Date(2026, 0, 1); 
        return reportDate >= thresholdDate ? 115000 : 135000;
    }, [reportDate]);

    const feeData = useMemo(() => {
        if (!grandTotal) return null;

        const theoryTotal = grandTotal.theory.total * BASE_FEE_RATES.theory;
        const simulationTotal = grandTotal.simulation.total * BASE_FEE_RATES.simulation;
        const practicalCourseTotal = grandTotal.practicalCourse.total * BASE_FEE_RATES.practicalCourse;
        const onRoadTotal = grandTotal.onRoad.total * BASE_FEE_RATES.onRoad;

        // Tính tiền lệ phí cấp GPLX dựa trên số người đạt sau cùng (finalPass)
        const licensingTotal = grandTotal.finalPass * licensingFeeRate;

        const totalExaminationFee = theoryTotal + simulationTotal + practicalCourseTotal + onRoadTotal;
        const grandTotalFee = totalExaminationFee + licensingTotal;

        return {
            theory: { count: grandTotal.theory.total, total: theoryTotal },
            simulation: { count: grandTotal.simulation.total, total: simulationTotal },
            practicalCourse: { count: grandTotal.practicalCourse.total, total: practicalCourseTotal },
            onRoad: { count: grandTotal.onRoad.total, total: onRoadTotal },
            licensing: { count: grandTotal.finalPass, total: licensingTotal },
