import React, { Component, ErrorInfo, ReactNode } from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

interface Props { 
    children?: ReactNode; 
}
interface State { 
    hasError: boolean; 
    error: Error | null; 
}

// FIX: Explicitly extending 'Component' from the named import to ensure 'this.props' and 'this.state' are correctly inherited and typed.
class ErrorBoundary extends Component<Props, State> {
    // FIX: Initialize state as a class property for better compatibility with strict TypeScript configurations.
    public state: State = { hasError: false, error: null };

    // FIX: Explicitly defining a constructor and calling super(props) to ensure 'this.props' is correctly populated.
    constructor(props: Props) {
        super(props);
    }

    static getDerivedStateFromError(error: Error): State {
        return { hasError: true, error };
    }

    componentDidCatch(error: Error, info: ErrorInfo) {
        console.error("Uncaught error:", error, info);
    }

    render() {
        // FIX: Accessing this.state through inheritance from Component.
        if (this.state.hasError) {
            return (
                <div className="flex flex-col items-center justify-center h-screen bg-red-50 p-6 text-center">
                    <h1 className="text-2xl font-bold text-red-800 mb-4">Lỗi Hệ Thống APPBCTH</h1>
                    <div className="bg-white p-4 rounded border text-left text-xs font-mono max-w-xl overflow-auto mb-4">
                        {this.state.error?.toString()}
                    </div>
                    <button onClick={() => window.location.reload()} className="px-6 py-2 bg-red-600 text-white font-bold rounded hover:bg-red-700">
                        <i className="fa-solid fa-rotate-right mr-2"></i> Tải lại trang
                    </button>
                </div>
            );
        }

        // FIX: Accessing this.props.children directly to ensure the compiler recognizes the inherited property correctly.
        return this.props.children;
    }
}

const rootEl = document.getElementById('root');
if (rootEl) {
    const root = ReactDOM.createRoot(rootEl);
    root.render(
        <React.StrictMode>
            <ErrorBoundary>
                <App />
            </ErrorBoundary>
        </React.StrictMode>
    );
}

import type { StudentRecord, TrainingUnit, SavedSession, ConflictWarning } from '../types';

// Helper chuẩn hóa ID để so khớp
const normalizeIdForMatch = (id: string | number | undefined): string => {
    if (id === undefined || id === null) return '';
    return String(id).trim().toUpperCase().replace(/^0+/, '');
};

export const getResultStatus = (result: string | number | undefined | null): { participated: boolean, passed: boolean } => {
    if (result === undefined || result === null) return { participated: false, passed: false };
    const normalized = result.toString().trim().toUpperCase();
    if (normalized === '' || normalized === 'VẮNG' || normalized === 'V') return { participated: false, passed: false };

    // Bất kỳ giá trị nào khác rỗng/Vắng đều được coi là có tham gia thi
    const isPassed = normalized === 'ĐẠT' || normalized === 'PASSED' || normalized === 'P' || normalized === '1' || normalized === 'CHẠM';
    return { participated: true, passed: isPassed };
};

export const isStudentAbsent = (record: StudentRecord): boolean => {
    const theory = getResultStatus(record['LÝ THUYẾT']);
    const simulation = getResultStatus(record['MÔ PHỎNG']);
    const practical = getResultStatus(record['SA HÌNH']);
    const onRoad = getResultStatus(record['ĐƯỜNG TRƯỜNG']);

    // Vắng là khi không tham gia bất kỳ môn nào trong 4 môn
    return !theory.participated && !simulation.participated && !practical.participated && !onRoad.participated;
};

export const isStudentPassed = (record: StudentRecord): boolean => {
    const theory = getResultStatus(record['LÝ THUYẾT']);
    const simulation = getResultStatus(record['MÔ PHỎNG']);
    const practical = getResultStatus(record['SA HÌNH']);
    const onRoad = getResultStatus(record['ĐƯỜNG TRƯỜNG']);

    const participatedInAnything = theory.participated || simulation.participated || practical.participated || onRoad.participated;
    if (!participatedInAnything) return false;

    // "CÁCH TÍNH CŨ": Nếu tham gia môn nào thì phải Đạt môn đó. 
    // Nếu chỉ thi 1 môn (thi lại) và Đạt môn đó thì coi như Đạt cả kỳ.
    if (theory.participated && !theory.passed) return false;
    if (simulation.participated && !simulation.passed) return false;
    if (practical.participated && !practical.passed) return false;
    if (onRoad.participated && !onRoad.passed) return false;

    return true;
};

export const checkHistoricalConflicts = (
    currentRecords: StudentRecord[],
    history: SavedSession[],
    currentSessionId: string = "new-upload"
): ConflictWarning[] => {
    const warnings: ConflictWarning[] = [];
    const studentHistory = new Map<string, { passed: Set<string>, lastSession: { name: string, date: string } }>();

    history.forEach(session => {
        if (session.id === currentSessionId) return;
        const sessionDate = new Date(session.reportDate).toLocaleDateString('vi-VN');

        session.studentRecords.forEach(record => {
            const sid = normalizeIdForMatch(record['MÃ HỌC VIÊN']);
            if (!sid) return;
            if (!studentHistory.has(sid)) studentHistory.set(sid, { passed: new Set(), lastSession: { name: session.name, date: sessionDate } });

            const historyData = studentHistory.get(sid)!;
            if (getResultStatus(record['LÝ THUYẾT']).passed) historyData.passed.add('L');
            if (getResultStatus(record['MÔ PHỎNG']).passed) historyData.passed.add('M');
            if (getResultStatus(record['SA HÌNH']).passed) historyData.passed.add('H');
            if (getResultStatus(record['ĐƯỜNG TRƯỜNG']).passed) historyData.passed.add('D');
        });
    });

    currentRecords.forEach(record => {
        const sid = normalizeIdForMatch(record['MÃ HỌC VIÊN']);
        const historyData = studentHistory.get(sid);
        if (!historyData) return;

        const currentParts = String(record['NỘI DUNG THI'] || '').toUpperCase().replace(/Đ/g, 'D');
        ['L', 'M', 'H', 'D'].forEach(p => {
            if (currentParts.includes(p) && historyData.passed.has(p)) {
                warnings.push({
                    studentName: record['HỌ VÀ TÊN'],
                    studentId: String(record['MÃ HỌC VIÊN']),
                    conflictPart: `Môn ${p === 'L' ? 'Lý thuyết' : p === 'M' ? 'Mô phỏng' : p === 'H' ? 'Sa hình' : 'Đường trường'} đã ĐẠT trước đó`,
                    previousSessionName: historyData.lastSession.name,
                    previousDate: historyData.lastSession.date,
                    sourceSessionId: currentSessionId
                });
            }
        });
    });
    return warnings;
};

export const generateClassSummaryString = (students: StudentRecord[]): string => {
    if (!students || students.length === 0) return "Tổng số: 0";
    const classCounts: { [key: string]: number } = {};
    for (const student of students) {
        const className = String(student['HẠNG GPLX'] || 'Khác').trim();
        classCounts[className] = (classCounts[className] || 0) + 1;
    }
    const sortedClasses = Object.keys(classCounts).sort();
    const parts = sortedClasses.map(className => `Hạng ${className}: ${classCounts[className]}`);
    return `Tổng số: ${students.length}\u00A0\u00A0\u00A0\u00A0${parts.join('; ')}`;
};

export const generateGhiChu = (record: StudentRecord): string => {
    const maHocVien = (record['MÃ HỌC VIÊN'] || '').toString().trim();
    const isRetake = maHocVien.startsWith('2721') || maHocVien.startsWith('2722');
    if (isRetake) return `Thi lại: ${record['NỘI DUNG THI'] || ''}`;
    return `Thi lần đầu`;
};

export const identifyTrainingUnit = (studentId: string | number | undefined, units: TrainingUnit[] = []): string => {
    if (!studentId || !units || units.length === 0) return '';
    const sId = studentId.toString().trim();
    const sortedUnits = [...units].sort((a, b) => b.code.length - a.code.length);
    const matchedUnit = sortedUnits.find(u => sId.startsWith(u.code));
    return matchedUnit ? matchedUnit.name : '';
};

import type { AppData, LicenseClassData, StudentRecord } from '../types';
import { getResultStatus, isStudentAbsent, isStudentPassed } from './reportUtils';

export const normalizeRecord = (record: any): StudentRecord => {
    const normalized: any = {};
    const keyMap: {[key: string]: string} = {
        'SỐ BÁO DANH': 'SỐ BÁO DANH', 'SBD': 'SỐ BÁO DANH',
        'MÃ HỌC VIÊN': 'MÃ HỌC VIÊN', 'MÃ HV': 'MÃ HỌC VIÊN',
        'HỌ VÀ TÊN': 'HỌ VÀ TÊN', 'HỌ TÊN': 'HỌ VÀ TÊN',
        'HẠNG GPLX': 'HẠNG GPLX', 'HẠNG': 'HẠNG GPLX',
        'NỘI DUNG THI': 'NỘI DUNG THI', 'ND THI': 'NỘI DUNG THI',
        'LÝ THUYẾT': 'LÝ THUYẾT', 'LT': 'LÝ THUYẾT',
        'MÔ PHỎNG': 'MÔ PHỎNG', 'MP': 'MÔ PHỎNG',
        'SA HÌNH': 'SA HÌNH', 'SH': 'SA HÌNH',
        'ĐƯỜNG TRƯỜNG': 'ĐƯỜNG TRƯỜNG', 'ĐT': 'ĐƯỜNG TRƯỜNG', 'DT': 'ĐƯỜNG TRƯỜNG',
        'SỐ CHỨNG MINH': 'SỐ CHỨNG MINH', 'CCCD': 'SỐ CHỨNG MINH',
        'NGÀY SINH': 'NGÀY SINH', 'NS': 'NGÀY SINH',
        'NƠI CƯ TRÚ': 'NƠI CƯ TRÚ'
    };

    Object.keys(record).forEach(key => {
        const cleanKey = key.trim().toUpperCase().replace(/\s+/g, ' ');
        const mapped = keyMap[cleanKey] || cleanKey;
        normalized[mapped] = record[key];
    });

    return normalized as StudentRecord;
};

const createEmptyClass = (className: string): LicenseClassData => ({
    class: className,
    totalApplications: 0,
    totalParticipants: 0,
    theory: { total: 0, pass: 0, fail: 0 },
    simulation: { total: 0, pass: 0, fail: 0 },
    practicalCourse: { total: 0, pass: 0, fail: 0 },
    onRoad: { total: 0, pass: 0, fail: 0 },
    finalPass: 0,
});

export const normalizeData = (raw: any[]): StudentRecord[] => raw.map(normalizeRecord);

export const processExcelData = (rawRecords: StudentRecord[]): AppData => {
    const firstTime: Record<string, LicenseClassData> = {};
    const retake: Record<string, LicenseClassData> = {};

    rawRecords.forEach(record => {
        const className = String(record['HẠNG GPLX'] || '').trim();
        if (!className) return;

        const maHV = String(record['MÃ HỌC VIÊN'] || '').trim();
        const isRetake = maHV.startsWith('2721') || maHV.startsWith('2722');
        const target = isRetake ? retake : firstTime;

        if (!target[className]) target[className] = createEmptyClass(className);
        const data = target[className];

        data.totalApplications++;
        if (!isStudentAbsent(record)) data.totalParticipants++;

        // "CÁCH TÍNH CŨ": Đếm dựa trên sự hiện diện của dữ liệu trong các cột, không quan tâm cột Nội dung thi

        const theory = getResultStatus(record['LÝ THUYẾT']);
        if (theory.participated) {
            data.theory.total++;
            if (theory.passed) data.theory.pass++;
        }

        const sim = getResultStatus(record['MÔ PHỎNG']);
        if (sim.participated) {
            data.simulation.total++;
            if (sim.passed) data.simulation.pass++;
        }

        const field = getResultStatus(record['SA HÌNH']);
        if (field.participated) {
            data.practicalCourse.total++;
            if (field.passed) data.practicalCourse.pass++;
        }

        const road = getResultStatus(record['ĐƯỜNG TRƯỜNG']);
        if (road.participated) {
            data.onRoad.total++;
            if (road.passed) data.onRoad.pass++;
        }

        if (isStudentPassed(record)) data.finalPass++;
    });

    const finalize = (obj: Record<string, LicenseClassData>) => 
        Object.values(obj)
            .map(v => ({
                ...v,
                theory: { ...v.theory, fail: Math.max(0, v.theory.total - v.theory.pass) },
                simulation: { ...v.simulation, fail: Math.max(0, v.simulation.total - v.simulation.pass) },
                practicalCourse: { ...v.practicalCourse, fail: Math.max(0, v.practicalCourse.total - v.practicalCourse.pass) },
                onRoad: { ...v.onRoad, fail: Math.max(0, v.onRoad.total - v.onRoad.pass) }
            }))
            .sort((a, b) => a.class.localeCompare(b.class));

    return {
        firstTime: { title: 'a) Học viên dự thi lần đầu:', rows: finalize(firstTime) },
        retake: { title: 'b) Thí sinh thuộc đối tượng cấp lại giấy phép lái xe và thí sinh tự do:', rows: finalize(retake) }
    };
};

