export const exportGeneralReportToExcel = (
    summaryData: AppData,
    grandTotal: LicenseClassData | null,
    reportDate: Date,
    reportMetadata: ReportMetadata
) => {
    if (!grandTotal) return;
    const wb = XLSX.utils.book_new();
    const ws = {};
    let R = 0;
    const merges: any[] = [];

    // Header
    ws['A1'] = { v: 'CÔNG AN TỈNH BẮC NINH', s: s.header };
    ws['J1'] = { v: 'CỘNG HÒA XÃ HỘI CHỦ NGHĨA VIỆT NAM', s: s.header };
    merges.push({ s: { r: 0, c: 0 }, e: { r: 0, c: 3 } }, { s: { r: 0, c: 9 }, e: { r: 0, c: 15 } });
    ws['A2'] = { v: 'PHÒNG CSGT', s: s.header };
    ws['J2'] = { v: 'Độc lập - Tự do - Hạnh phúc', s: s.header };
    merges.push({ s: { r: 1, c: 0 }, e: { r: 1, c: 3 } }, { s: { r: 1, c: 9 }, e: { r: 1, c: 15 } });
    R = 3;
    ws[`J${R + 1}`] = { v: `Bắc Ninh, ngày ${reportDate.getDate()} tháng ${reportDate.getMonth() + 1} năm ${reportDate.getFullYear()}`, s: s.date };
    merges.push({ s: { r: R, c: 9 }, e: { r: R, c: 15 } });
    R += 3;
    ws[`A${R + 1}`] = { v: 'BIÊN BẢN TỔNG HỢP KẾT QUẢ KỲ SÁT HẠCH LÁI XE Ô TÔ', s: s.title };
    merges.push({ s: { r: R, c: 0 }, e: { r: R, c: 15 } });
    R += 2;

    // Các bảng kết quả
    const addTable = (title: string, rows: LicenseClassData[], isRetake: boolean) => {
        ws[`A${R + 1}`] = { v: title, s: s.bold }; R++;
        const headers = ["Hạng GPLX", "Tổng số hồ sơ", "Tổng số dự thi", "Thi lý thuyết", null, null, "Mô phỏng", null, null, "Sa hình", null, null, "Đường trường", null, null, "Kết quả đạt"];
        headers.forEach((h, c) => { if(h) ws[XLSX.utils.encode_cell({r:R, c})] = {v:h, s:s.tableHeader}});
        merges.push({s:{r:R,c:3}, e:{r:R,c:5}}, {s:{r:R,c:6}, e:{r:R,c:8}}, {s:{r:R,c:9}, e:{r:R,c:11}}, {s:{r:R,c:12}, e:{r:R,c:14}});
        R++;
        rows.forEach(row => {
            const cells = [row.class, row.totalApplications, row.totalParticipants, row.theory.total, row.theory.pass, row.theory.fail, row.simulation.total, row.simulation.pass, row.simulation.fail, row.practicalCourse.total, row.practicalCourse.pass, row.practicalCourse.fail, row.onRoad.total, row.onRoad.pass, row.onRoad.fail, row.finalPass];
            cells.forEach((v, c) => { ws[XLSX.utils.encode_cell({r:R, c})] = {v, s:s.cell}}); R++;
        });
        R++;
    };

    addTable(summaryData.firstTime.title, summaryData.firstTime.rows, false);
    addTable(summaryData.retake.title, summaryData.retake.rows, true);

    // Thu phí
    ws[`A${R+1}`] = { v: 'III. Tổng hợp số thu phí sát hạch và lệ phí cấp GPLX:', s: s.bold }; R++;
    const theoryTotal = grandTotal.theory.total * FEE_RATES.theory;
    const simTotal = grandTotal.simulation.total * FEE_RATES.simulation;
    const fieldTotal = grandTotal.practicalCourse.total * FEE_RATES.practicalCourse;
    const roadTotal = grandTotal.onRoad.total * FEE_RATES.onRoad;
    const licTotal = grandTotal.finalPass * FEE_RATES.licensing;
    const totalFee = theoryTotal + simTotal + fieldTotal + roadTotal + licTotal;

    const feeRows = [
        ['1', 'Lý thuyết', grandTotal.theory.total, FEE_RATES.theory, theoryTotal],
        ['2', 'Mô phỏng', grandTotal.simulation.total, FEE_RATES.simulation, simTotal],
        ['3', 'Sa hình', grandTotal.practicalCourse.total, FEE_RATES.practicalCourse, fieldTotal],
        ['4', 'Đường trường', grandTotal.onRoad.total, FEE_RATES.onRoad, roadTotal],
        ['', 'Lệ phí cấp GPLX', grandTotal.finalPass, FEE_RATES.licensing, licTotal],
        ['', 'TỔNG CỘNG', '', '', totalFee]
    ];
    feeRows.forEach(row => {
        row.forEach((v, c) => { ws[XLSX.utils.encode_cell({r:R, c:[0,1,3,4,5][c]})] = {v, s: c === 4 ? s.cell_right : s.cell}}); R++;
    });

    ws['!merges'] = merges;
    XLSX.utils.book_append_sheet(wb, ws, "BaoCao");
    XLSX.writeFile(wb, `Bien_Ban_${formatDateForFilename(reportDate)}.xlsx`);
};

